import type { LegalKnowledgeDocument } from '../legal-knowledge.types'

export const mervardesskattelagen: LegalKnowledgeDocument = {
  id: "mervardesskattelagen",
  titel: "Mervärdesskattelagen (1994:200) — utvalda kapitel",
  sfs: "1994:200",
  verifieradPer: "2026-05-29",
  kalla: "https://lagen.nu/1994:200",
  innehall: "# Mervärdesskattelagen (1994:200) — utvalda kapitel\n\n> Källa: https://lagen.nu/1994:200\n> Hämtad: 2026-05-29\n> Omfattar: kapitel 1, 3, 5, 8 (relevanta för fastighetsförvaltning)\n\nDessa kapitel utgör grunden för momsbedömning i fastighetsförvaltning. **3 kap. 2 §** undantar omsättning av fastigheter och upplåtelse av nyttjanderätter (arrenden, hyresrätter, bostadsrätter m.fl.) från skatteplikt — detta är huvudregeln som gör bostadshyror momsfria. **3 kap. 3 §** definierar undantagen från undantaget: hotellrumsuthyrning, parkering, korttidsuthyrning av idrottslokaler m.m. är skattepliktiga, och frivillig skattskyldighet öppnas för uthyrning av lokaler till verksamhet som medför skattskyldighet (kommersiella lokaler — kritiskt). **5 kap.** styr omsättningsland; särskilt **5 kap. 8 §** för fastighetsanknutna tjänster. **8 kap.** reglerar avdragsrätt för ingående moms — relevant för fastighetsägare med blandad verksamhet (proportionering enligt 8 kap. 13 §).\n\n# 1 kap. Inledande bestämmelser\n\n### Lagens tillämpningsområde\n\n## 1 §\n\nMervärdesskatt ska betalas till staten enligt denna lag\n\n1. vid sådan omsättning inom landet av varor eller tjänster som är skattepliktig och görs av en beskattningsbar person i denna egenskap, i den utsträckning den beskattningsbara personen inte är befriad från skatt på omsättningen,\n2. vid skattepliktigt unionsinternt förvärv av varor som är lös egendom, om inte omsättningen är gjord inom landet, eller\n3. vid sådan import av varor till landet som är skattepliktig.\n\nVad som utgör omsättning eller import anges i 2 kap. Vad som utgör unionsinternt förvärv anges i 2 a kap. I vilka fall det finns skatteplikt för en omsättning, ett unionsinternt förvärv eller import anges i 3 kap. Vad som avses med beskattningsbar person anges i 4 kap. I vilka fall en omsättning anses ha gjorts inom landet anges i 5 kap. Förutsättningarna för skattebefrielse anges i 9 d kap.\n\nTill staten ska också betalas belopp som i en faktura eller liknande handling betecknats som mervärdesskatt, även om beloppet inte utgör mervärdesskatt enligt denna lag. Lag (2016:1069).\n\n## 2 §\n\nSkyldig att betala mervärdesskatt (skattskyldig) är\n\n1. för sådan omsättning som anges i 1 § första stycket 1, om inte annat följer av 1 a-4 f: den som omsätter varan eller tjänsten,\n   1a. för sådan omsättning som anges i 1 § första stycket 1 av varor och tjänster som ska redovisas enligt bestämmelser som motsvarar de särskilda ordningarna i artiklarna 369a-369x i rådets direktiv 2006/112/EG av den 28 november 2006 om ett gemensamt system för mervärdesskatt, i lydelsen enligt direktiv (EU) 2017/2455 och direktiv 2019/1995, om den som omsätter varan eller tjänsten är en sådan grupp av personer som i ett annat EU-land anses som en enda beskattningsbar person (mervärdesskattegrupp): mervärdesskattegruppen,\n\n2. för omsättning som anges i 1 § första stycket 1 av sådana tjänster som avses i 5 kap. 5 §, om den som omsätter tjänsten är en utländsk beskattningsbar person: den som förvärvar tjänsten, om denne är\n\n- en beskattningsbar person,\n- en juridisk person som inte är en beskattningsbar person men är registrerad till mervärdesskatt här, eller\n- en juridisk person som skulle ha varit en beskattningsbar person om inte 4 kap. 8 § varit tillämplig,\n\n3. för omsättning som anges i 1 § första stycket 1 av sådana varor som avses i 5 kap.2 c och 2 d §§, om den som omsätter varan är en utländsk beskattningsbar person och förvärvaren är registrerad till mervärdesskatt här: den som förvärvar varan,\n4. för sådan efterföljande omsättning inom landet som avses i 3 kap. 30 b § första stycket: den till vilken omsättningen görs,\n   4a. för omsättning som anges i 1 § första stycket 1 mellan beskattningsbara personer som är eller ska vara registrerade till mervärdesskatt här, av guldmaterial eller halvfärdiga produkter med en finhalt av minst 325 tusendelar eller av investeringsguld om den som omsätter guldet är skattskyldig enligt 3 kap. 10 b § : den som förvärvar varan,\n\n4b. för omsättning som anges i 1 § första stycket 1 av sådana tjänster som avses i andra stycket, om skattskyldighet inte föreligger enligt första stycket 2 i denna paragraf: den som förvärvar tjänsten, om denne är\n\n- en beskattningsbar person som i sin verksamhet inte endast tillfälligt tillhandahåller sådana tjänster, eller\n- en annan beskattningsbar person som tillhandahåller en beskattningsbar person som avses i första strecksatsen sådana tjänster,\n  4c. för omsättning som anges i 1 § första stycket 1 av vara eller av tjänst med anknytning till fastighet som avses i 5 kap. 8 §, utom fastighetstjänst som avses i 4 b i denna paragraf eller 3 kap.3 § andra och tredje styckena, om den som omsätter varan eller tjänsten är en utländsk beskattningsbar person och förvärvaren är registrerad till mervärdesskatt här: den som förvärvar varan eller tjänsten, om inte annat följer av 2 d §,\n  4d. för omsättning som anges i 1 § första stycket 1 mellan beskattningsbara personer som är eller ska vara registrerade till mervärdesskatt här, om skattskyldighet inte föreligger enligt första stycket 2 i denna paragraf, av utsläppsrätter för växthusgaser enligt definitionen i artikel 3 i Europaparlamentets och rådets direktiv 2003/87/EG av den 13 oktober 2003 om ett system för handel med utsläppsrätter för växthusgaser inom gemenskapen vilka kan överlåtas enligt artikel 12 i det direktivet, eller av andra enheter som verksamhetsutövare kan använda för att följa det direktivet: den som förvärvar tjänsten,\n  4e. för omsättning som anges i 1 § första stycket 1 mellan beskattningsbara personer som är eller ska vara registrerade till mervärdesskatt här av sådana varor som avses i tredje stycket: den som förvärvar varan,\n  4f. för omsättning som anges i 1 § första stycket 1 mellan beskattningsbara personer som är eller ska vara registrerade till mervärdesskatt här av sådana varor som avses i sjunde stycket: den som förvärvar varan, om beskattningsunderlaget för omsättningen av dessa varor i en faktura sammantaget överstiger 100 000 kronor och registreringsskyldigheten för förvärvaren inte endast är en konsekvens av förvärvet,\n\n5. för sådant förvärv som anges i 1 § första stycket 2: den som förvärvar varan, och\n\n6. för import av varor\n   a) om en tullskuld uppkommer i Sverige till följd av importen: den som är skyldig att betala tullen, om inte annat följer av c,\n   b) om importen avser en unionsvara eller om varan ska deklareras för övergång till fri omsättning i Sverige men inte är belagd med tull: den som skulle ha varit skyldig att betala tullen om varan hade varit tullbelagd, om inte annat följer av c,\n   c) om den som är eller skulle ha varit skyldig att betala tullen enligt a eller b är ett ombud och Skatteverket är beskattningsmyndighet: den för vars räkning ombudet handlar,\n   d) om en tullskuld uppkommer i ett annat EU-land, eller skulle ha uppkommit om varan hade varit belagd med tull, till följd av att en tulldeklaration ges in i det landet med stöd av ett sådant tillstånd för centraliserad klarering som avses i artikel 179 i Europaparlamentets och rådets förordning (EU) nr 952/2013 av den 9 oktober 2013 om fastställande av en tullkodex för unionen: den som är eller skulle ha varit skyldig att betala tullen i det andra EU-landet, om inte annat följer av e,\n   e) om den som är eller skulle ha varit skyldig att betala tullen enligt d är ett ombud och Skatteverket är beskattningsmyndighet: den för vars räkning ombudet handlar.\n\nFörsta stycket 4 b gäller\n\n1. sådana tjänster avseende fastighet som kan hänföras till\n\n- mark- och grundarbeten,\n- bygg- och anläggningsarbeten,\n- bygginstallationer,\n- slutbehandling av byggnader, eller\n- uthyrning av bygg- och anläggningsmaskiner med förare,\n\n2. byggstädning, och\n3. uthyrning av arbetskraft för sådana aktiviteter som avses i 1 och 2.\n\nFörsta stycket 4 e gäller\n\n1. avfall och skrot av järn, stål, koppar, nickel, aluminium, bly, zink, tenn och andra oädla metaller,\n2. omsmältningsgöt av järn och stål, och\n3. avfall och skrot av galvaniska element, batterier och elektriska ackumulatorer.\n\nVid omsättning av en vara eller en tjänst som görs inom landet av en beskattningsbar person som har ett fast etableringsställe här ska den beskattningsbara personen vid tillämpningen av första stycket likställas med en utländsk beskattningsbar person, om omsättningen görs utan medverkan av det svenska etableringsstället.\n\nMed tullskuld och unionsvara förstås detsamma som i artikel 5 i förordning (EU) nr 952/2013.\n\nSärskilda bestämmelser om vem som i vissa fall är skattskyldig finns i 6 kap., 9 kap. och 9 c kap.\n\nFörsta stycket 4 f gäller följande varor:\n\n1. mobiltelefoner, det vill säga apparater som har tillverkats eller anpassats för användning i ett auktoriserat nät och på särskilt angivna frekvenser, oberoende av om de har någon annan användning eller inte,\n2. integrerade kretsanordningar, om dessa inte har integrerats i slutanvändningsprodukter, och\n3. spelkonsoler, pekdatorer och bärbara datorer. Lag (2021:1148).\n\n## 2 a §\n\nSkattskyldighet föreligger inte för en upphovsman eller dennes dödsbo för omsättning av sådana konstverk som avses i 9 a kap. 5 §, om\n\n1. konstverket vid omsättningen ägs av upphovsmannen eller dennes dödsbo, och\n2. beskattningsunderlagen för beskattningsåret sammanlagt understiger 300 000 kronor. Lag (1995:700).\n\n## 2 b §\n\nPå begäran av den som enligt 2 a § inte är skattskyldig skall Skatteverket besluta att skattskyldighet skall föreligga oavsett beskattningsunderlagens storlek. Skatteverkets beslut gäller till utgången av det andra året efter det år under vilket beslutet fattades. Lag (2003:659).\n\n## 2 c §\n\nSärskilda bestämmelser om mervärdesskatt finns i lagen (2000:142) om avtal med Danmark om mervärdesskatt för den fasta vägförbindelsen över Öresund. Lag (2000:143).\n\n## 2 d §\n\nEn utländsk beskattningsbar person som begär det har rätt att bli skattskyldig för omsättning som annars förvärvaren skulle ha varit skattskyldig för enligt 2 § första stycket 4 c. Den utländska beskattningsbara personens skattskyldighet ska därvid gälla för all sådan omsättning inom landet.\n\nVid omsättning av en vara eller en tjänst som görs inom landet av en beskattningsbar person som har ett fast etableringsställe här ska den beskattningsbara personen vid tillämpningen av första stycket likställas med en utländsk beskattningsbar person, om omsättningen görs utan medverkan av det svenska etableringsstället. Lag (2013:368).\n\n### Skyldighet att betala felaktigt debiterad mervärdesskatt\n\n## 2 e §\n\nDen som anger ett sådant belopp som avses i 1 § tredje stycket på en faktura eller liknande handling är betalningsskyldig för beloppet. Lag (2007:1376).\n\n### Tidpunkten för skattskyldighetens inträde\n\n## 3 §\n\nSkyldigheten att betala skatt enligt 1 § vid omsättning inträder när varan har levererats eller tjänsten har tillhandahållits eller när varan eller tjänsten har tagits i anspråk genom uttag, om inte annat följer av andra stycket eller 3 a, 3 b, 4, 5 a eller 5 b §.\n\nOm den som omsätter varan eller tjänsten får ersättning helt eller delvis för en beställd vara eller tjänst före den tidpunkt som avses i första stycket, inträder skattskyldigheten när ersättningen inflyter kontant eller på annat sätt kommer den som omsätter varan eller tjänsten till godo. Detta gäller dock endast om omsättningen är skattepliktig när ersättningen kommer den som omsätter varan eller tjänsten till godo.\n\nMed leverans av en vara förstås att varan avlämnas eller att den sänds till en köpare mot postförskott eller efterkrav. En överlåtelse av en enfunktionsvoucher ska vid tillämpning av första stycket likställas med en leverans av de varor eller ett tillhandahållande av de tjänster som vouchern avser. Lag (2020:1170).\n\n## 3 a §\n\nVid omsättning av bygg- och anläggningstjänster och av varor som omsätts i samband med sådana tjänster inträder skyldigheten att betala skatt när faktura har utfärdats. Om någon faktura inte har utfärdats när betalning erhålls, eller om faktura inte har utfärdats inom den tid som anges i 11 kap. 3 a § första stycket, inträder skattskyldigheten enligt 3 §. Lag (2012:342).\n\n## 3 b §\n\nNär omsättningen avser en personbil eller motorcykel som vid leveransen är tillfälligt registrerad enligt 17 § första stycket 1 lagen (2019:370) om fordons registrering och användning och fordonet levereras till en fysisk person, som är bosatt eller stadigvarande vistas i ett annat land än ett EU-land och som avser att föra fordonet till en plats utanför EU, inträder skyldigheten att betala skatt vid utgången av den sjätte månaden efter den månad då fordonet levererades. Lag (2019:373).\n\n## 4 §\n\nI fråga om upplåtelse av avverkningsrätt till skog i de fall som avses i 21 kap. 2 § inkomstskattelagen (1999:1229) inträder skattskyldigheten allteftersom betalningen tas emot av upplåtaren. Lag (2007:1376).\n\n## 4 a §\n\nVid unionsinterna förvärv inträder skattskyldigheten vid tidpunkten för förvärvet. Denna tidpunkt ska anses vara densamma som den då skattskyldighet inträder enligt 3 § första stycket vid motsvarande omsättning av varor inom landet.\n\nVid unionsinterna förvärv av varor som levereras kontinuerligt under mer än en kalendermånad inträder skattskyldigheten för förvärvet vid utgången av varje kalendermånad, om inte leveransen upphört innan dess. Lag (2012:342).\n\n## 5 §\n\nVid import inträder skattskyldigheten vid den tidpunkt då tullskulden uppkommer i Sverige enligt tullagstiftningen, eller skulle ha uppkommit om varan hade varit belagd med tull.\n\nI de fall som avses i 2 § första stycket 6 d eller e inträder skattskyldigheten vid den tidpunkt då tullskulden uppkommer eller skulle ha uppkommit i det andra EU-landet. Lag (2021:1148).\n\n## 5 a §\n\nVid förvärv av tjänster som avses i 1 kap. 2 § första stycket 2 inträder skattskyldigheten den 31 december varje år, om\n\n1. tjänsterna tillhandahålls kontinuerligt under en tidsperiod som överstiger ett år, och\n2. tillhandahållandet inte ger upphov till avräkningar eller betalningar under tidsperioden.\n\nFörsta stycket gäller inte om tillhandahållandet av tjänsterna har upphört. Lag (2009:1333).\n\n## 5 b §\n\nOm en beskattningsbar person har förvärvat och omsatt varor enligt 6 kap.9 eller 10 §, inträder skyldigheten att betala skatt för både förvärvet och omsättningen när betalningen har godkänts.\n\nSkyldigheten att betala skatt vid distansförsäljning av varor importerade från ett land utanför EU för vilken skatt ska redovisas enligt lagen (2011:1245) om särskilda ordningar för mervärdesskatt för distansförsäljning av varor och för tjänster inträder när betalningen har godkänts. Lag (2020:1170).\n\n### Innebörden av vissa uttryck i denna lag\n\n## 6 §\n\nMed vara förstås materiella ting, bland dem fastigheter och gas, samt värme, kyla och elektrisk kraft. Med tjänst förstås allt annat som kan tillhandahållas. Lag (2013:368).\n\n## 7 §\n\nVad som föreskrivs i fråga om verksamhet avser såväl hela verksamheten som en del av verksamheten. I 13 kap. avses dock hela verksamheten om inte något annat anges.\n\nMed verksamhet som medför skattskyldighet förstås en sådan verksamhet i vilken omsättning av varor eller tjänster medför skattskyldighet enligt 2 § första stycket 1.Lag (1997:502).\n\n## 8 §\n\nMed utgående skatt förstås sådan skatt som ska redovisas till staten vid omsättning, unionsinternt förvärv eller import enligt 1 §.\n\nMed ingående skatt förstås sådan skatt vid förvärv eller import som anges i 8 kap. 2 §. Lag (2011:283).\n\n## 9 §\n\nMed marknadsvärde förstås hela det belopp som köparen av en vara eller tjänst, i samma försäljningsled som det där omsättningen av varan eller tjänsten äger rum, vid tidpunkten för omsättningen och i fri konkurrens, skulle få betala till en oberoende säljare inom landet för en sådan vara eller tjänst.\n\nOm ingen jämförbar omsättning av varor eller tjänster kan fastställas, utgörs marknadsvärdet\n\n1. när det gäller varor, av ett belopp som inte understiger inköpspriset för varorna eller för liknande varor eller, om inköpspris saknas, självkostnadspriset, fastställt vid tidpunkten för transaktionen, eller\n2. när det gäller tjänster, av ett belopp som inte understiger den beskattningsbara personens kostnad för att utföra tjänsten. Lag (2013:368).\n\n## 10 §\n\nMed export avses sådan omsättning utanför EU av varor eller tjänster som görs i en ekonomisk verksamhet som bedrivs här i landet. Lag (2013:368).\n\n## 10 a §\n\nMed EU eller ett EU-land förstås i denna lag de territorier som tillhör en medlemsstat enligt artikel 52 i fördraget om Europeiska unionen och artikel 355 i fördraget om Europeiska unionens funktionssätt. Det gäller dock inte de territorier som anges i 10 b §.\n\nVid tillämpningen av denna lag ska Furstendömet Monaco, Isle of Man och Förenade kungarikets suveräna basområden Akrotiri och Dhekelia likställas med sådana territorier som avses i första stycket första meningen. Lag (2011:283).\n\n## 10 b §\n\nMed ett tredje territorium förstås:\n\n1. berget Athos,\n2. Kanarieöarna,\n3. de franska territorier som avses i artiklarna 349 och 355.1 i fördraget om Europeiska unionens funktionssätt,\n4. Åland,\n5. Kanalöarna,\n6. Campione d'Italia,\n7. de italienska delarna av Luganosjön,\n8. ön Helgoland,\n9. territoriet Büsingen,\n10. Ceuta,\n11. Melilla,\n12. Livigno.\n\nTerritorierna i första stycket 1-7 ingår i unionens tullområde medan de i 8-12 samma stycke angivna territorierna inte ingår i området. Lag (2019:789).\n\n## 10 c §\n\nTransaktioner med ursprung i eller avsedda för\n\n1. Furstendömet Monaco ska behandlas som transaktioner med ursprung i eller avsedda för Frankrike,\n2. Isle of Man ska behandlas som transaktioner med ursprung i eller avsedda för Förenade kungariket,\n3. Förenade kungarikets suveräna basområden Akrotiri och Dhekelia ska behandlas som transaktioner med ursprung i eller avsedda för Cypern. Lag (2010:1892).\n\n## 11 §\n\nMed fastighet avses fast egendom enligt artikel 13b i rådets genomförandeförordning (EU) nr 282/2011 av den 15 mars 2011 om fastställande av tillämpningsföreskrifter för direktiv 2006/112/EG om ett gemensamt system för mervärdesskatt. Lag (2016:1208).\n\n## 13 §\n\nMed personbil förstås även lastbil med skåpkarosseri och buss, om fordonets totalvikt är högst 3 500 kilogram. Detta gäller dock inte om lastbilens förarhytt utgör en separat karosserienhet.\n\nMed personbil förstås i 2 kap. 5 § 3, 7 kap. 4 §, 8 kap.10, 15 och 16 §§ samt 13 kap. 15 § dock inte fordon som är personbil klass II enligt 2 § lagen (2001:559) om vägtrafikdefinitioner och har en totalvikt som\n\n1. överstiger 3 500 kilogram, eller\n2. är högst 3 500 kilogram, om fordonets förarhytt utgör en separat karosserienhet. Lag (2013:1105).\n\n## 13 a §\n\nMed nya transportmedel förstås\n\n1. motordrivna marktransportmedel som är avsedda för transporter till lands av personer eller varor och som har en motor med en cylindervolym om mer än 48 kubikcentimeter eller en effekt om mer än 7,2 kilowatt, om de omsätts inom sex månader efter det att de första gången tagits i bruk eller före omsättningen har körts högst 6 000 kilometer,\n2. fartyg vars längd överstiger 7,5 meter, utom sådana fartyg som anges i 3 kap. 21 a §, om de omsätts inom tre månader efter det att de första gången tagits i bruk eller före omsättningen har färdats högst 100 timmar, och\n3. luftfartyg vars startvikt överstiger 1 550 kilogram, utom sådana luftfartyg som anges i 3 kap. 21 §, om de omsätts inom tre månader efter det att de första gången tagits i bruk eller före omsättningen har flugits högst 40 timmar. Lag (2017:1196).\n\n## 13 b §\n\nMed punktskattepliktiga varor avses energiprodukter, alkohol, alkoholhaltiga drycker eller tobaksvaror såsom dessa varor definieras i unionslagstiftningen för punktskatter. Det gäller dock inte gas som levereras genom ett naturgassystem som är beläget inom unionens territorium eller genom ett gasnät som är anslutet till ett sådant system. Lag (2011:283).\n\n## 14 §\n\nMed beskattningsår förstås beskattningsår enligt inkomstskattelagen (1999:1229).\n\nOm skatt enligt denna lag hänför sig till en verksamhet för vilken skattskyldighet inte föreligger enligt inkomstskattelagen, förstås med beskattningsår\n\n1. kalenderåret, eller\n2. räkenskapsåret, om detta är brutet och överensstämmer med vad som anges i 3 kap.bokföringslagen (1999:1078).\n\nI ärenden om återbetalning av ingående skatt till en sådan beskattningsbar person som avses i 19 kap.1 § första och andra styckena förstås med beskattningsår det kalenderår som ansökan om återbetalning gäller.\n\nMed beskattningsår förstås dock kalenderåret när det gäller skatt enligt denna lag som redovisas enligt\n\n1. lagen (2011:1245) om särskilda ordningar för mervärdesskatt för distansförsäljning av varor och för tjänster, eller\n2. bestämmelser som i ett annat EU-land motsvarar artiklarna 358a-369, 369a-369k eller 369l-369x i rådets direktiv 2006/112/EG. Lag (2020:1170).\n\n## 15 §\n\nMed utländsk beskattningsbar person förstås en beskattningsbar person som inte har sätet för sin ekonomiska verksamhet eller ett fast etableringsställe här i landet och inte heller är bosatt eller stadigvarande vistas här. Lag (2013:368).\n\n## 16 §\n\nMed staten avses inte de statliga affärsverken. Med kommun förstås kommun och region enligt kommunallagen (2017:725). Lag (2019:886).\n\n## 17 §\n\nMed faktura avses dokument eller meddelanden i pappersform eller i elektronisk form som uppfyller villkoren för fakturor i 11 kap. eller, om faktureringsreglerna i ett annat EU-land är tillämpliga enligt vad som följer av artikel 219a i rådets direktiv 2006/112/EG, som uppfyller villkoren för fakturor i det landet. Lag (2014:940).\n\n## 17 a §\n\nMed elektronisk faktura avses en faktura enligt 17 § som utfärdas och tas emot i ett elektroniskt format. Lag (2012:342).\n\n## 18 §\n\nMed investeringsguld förstås\n\n1. guld i form av en tacka eller platta med en vikt som godtas på någon av marknaderna för sådant guld och med en finhalt av minst 995 tusendelar, oavsett om guldet representeras av värdepapper eller inte,\n\n2. guldmynt som\n\n- har en finhalt av minst 900 tusendelar,\n- är präglade efter år 1800,\n- är eller har varit gällande betalningsmedel i ursprungslandet, och\n- normalt säljs till ett pris som inte överstiger marknadsvärdet för guldinnehållet i myntet med mer än 80 %.\n\nSmå tackor eller plattor med en vikt av 1 gram eller mindre omfattas inte av första stycket 1.\n\nGuldmynt som omfattas av den förteckning som årligen offentliggörs i C-serien av Europeiska unionens officiella tidning ska anses uppfylla kriterierna i första stycket 2 under hela det år förteckningen gäller.\n\nGuldmynt enligt denna paragraf ska inte anses omsatta på grund av det numismatiska värdet. Lag (2011:283).\n\n## 19 §\n\nMed fri omsättning förstås detsamma som i Europaparlamentets och rådets förordning (EU) nr 952/2013 av den 9 oktober 2013 om fastställande av en tullkodex för unionen. Lag (2016:261).\n\n## 20 §\n\nMed voucher avses ett instrument för vilket det finns en skyldighet att godta det som ersättning eller partiell ersättning för leverans av varor eller tillhandahållande av tjänster. De varor som ska levereras eller tjänster som ska tillhandahållas eller de potentiella leverantörernas eller tillhandahållarnas identitet måste anges antingen på instrumentet eller i tillhörande dokumentation som inbegriper villkoren för användning av instrumentet. Lag (2018:1333).\n\n## 21 §\n\nMed enfunktionsvoucher avses en voucher för vilken det redan när den ställs ut är känt med vilket belopp mervärdesskatt ska betalas för de varor och tjänster som vouchern avser och i vilket land omsättningen av varorna eller tjänsterna ska anses ha skett.\n\nMed flerfunktionsvoucher avses en annan voucher än en enfunktionsvoucher. Lag (2018:1333).\n\n# 3 kap. Skatteplikt för omsättning, unionsinternt förvärv och import\n\n### Generell skatteplikt\n\n## 1 §\n\nOmsättning av varor och tjänster samt import är skattepliktiga, om inget annat anges i detta kapitel.\n\nÄr omsättningen av en vara undantagen från skatteplikt enligt detta kapitel, är även import av varan undantagen från skatteplikt.\n\nUnionsinternt förvärv är skattepliktigt om motsvarande omsättning skulle ha varit det. Lag (2011:283).\n\n## 1 a §\n\nI 9 c kap. finns särskilda bestämmelser om undantag från skatteplikt under den tid som varor är placerade i vissa lager. Lag (1995:1286).\n\n### Undantag på fastighetsområdet\n\n## 2 §\n\nFrån skatteplikt undantas, med de begränsningar som följer av 3 §, omsättning av fastigheter samt överlåtelse och upplåtelse av arrenden, hyresrätter, bostadsrätter, tomträtter, servitutsrätter och andra rättigheter till fastigheter.\n\nUndantaget för upplåtelse av nyttjanderätter till fastigheter omfattar också underordnade tillhandahållanden, exempelvis upplåtarens tillhandahållande av gas, vatten, elektricitet, värme och nätutrustning för mottagning av radio- och televisionssändningar, om tillhandahållandet är en del av upplåtelsen av nyttjanderätten. Lag (2016:1208).\n\n## 3 §\n\nUndantaget enligt 2 § omfattar inte\n\n1. upplåtelse eller överlåtelse av maskiner och utrustning som har installerats varaktigt,\n2. omsättning av växande skog, odling och annan växtlighet utan samband med överlåtelse av marken,\n3. upplåtelse eller överlåtelse av rätt till jordbruksarrende, avverkningsrätt och annan jämförlig rättighet, rätt att ta jord, sten eller andra naturprodukter samt rätt till jakt, fiske eller bete,\n4. rumsuthyrning i hotellrörelse eller liknande verksamhet samt upplåtelse av campingplatser och motsvarande i campingverksamhet,\n5. upplåtelse av lokaler och andra platser för parkering, inklusive förtöjning och ankring, av transportmedel,\n6. upplåtelse av förvaringsboxar,\n7. upplåtelse av utrymmen för reklam eller annonsering på fastigheter,\n8. upplåtelse för djur av byggnader eller mark,\n9. upplåtelse för trafik av väg, bro eller tunnel samt upplåtelse av spåranläggning för järnvägstrafik,\n10. korttidsupplåtelse av lokaler och anläggningar för idrottsutövning,\n11. upplåtelse av terminalanläggning för buss- och tågtrafik till trafikoperatörer, och\n12. upplåtelse till en mobiloperatör av plats för utrustning på en mast eller liknande konstruktion och tillhörande utrymme för teknisk utrustning som omfattas av upplåtelsen.\n\nUndantaget enligt 2 § gäller inte heller när en fastighetsägare, ett konkursbo eller en sådan mervärdesskattegrupp som avses i 6 a kap. för stadigvarande användning i en verksamhet som medför skattskyldighet eller som medför rätt till återbetalning enligt 10 kap. 1, 6, 6 a, 9, 11, 11 e eller 12 § helt eller delvis hyr ut en sådan byggnad eller annan anläggning, som utgör fastighet. Skatteplikt gäller dock inte om uthyrningen avser stadigvarande bostad. Uthyrning till staten, en kommun, ett kommunalförbund eller ett samordningsförbund som avses i 4 § lagen (2003:1210) om finansiell samordning av rehabiliteringsinsatser är skattepliktig även om uthyrningen sker för en verksamhet som inte medför skattskyldighet eller rätt till återbetalning enligt 10 kap. 1, 6, 6 a, 9, 11, 11 e eller 12 §. Skatteplikt gäller dock inte för uthyrning till en kommun, ett kommunalförbund eller ett samordningsförbund, om fastigheten vidareuthyrs av kommunen, kommunalförbundet eller samordningsförbundet för användning i en verksamhet som bedrivs av någon annan än staten, en kommun, ett kommunalförbund eller ett samordningsförbund och som inte medför skattskyldighet eller rätt till återbetalning enligt 10 kap. 1, 6, 6 a, 9, 11, 11 e eller 12 §. Det som har sagts om uthyrning gäller även för upplåtelse av bostadsrätt.\n\nAndra stycket tillämpas också\n\n1. vid uthyrning i andra och tredje hand,\n2. vid bostadsrättshavares upplåtelse av nyttjanderätt till fastighet som innehas med bostadsrätt, och\n3. när en byggnad eller annan anläggning som utgör fastighet uppförs eller genomgår omfattande till- eller ombyggnad i syfte att anläggningen helt eller delvis ska kunna hyras ut för sådan verksamhet som avses i andra stycket.\n\nI 9 kap. finns särskilda bestämmelser om skattskyldighet för sådan uthyrning, bostadsrättsupplåtelse och upplåtelse av nyttjanderätt som anges i andra och tredje styckena. Lag (2021:1185).\n\n### Undantag för sjukvård, tandvård och social omsorg\n\n## 4 §\n\nFrån skatteplikt undantas omsättning av tjänster som utgör sjukvård, tandvård eller social omsorg samt tjänster av annat slag och varor som den som tillhandahåller vården eller omsorgen omsätter som ett led i denna.\n\nUndantaget omfattar även\n\n- kontroller och analyser av prov som tagits som ett led i sjukvården eller tandvården, och\n- omsättning av dentaltekniska produkter och av tjänster som avser sådana produkter, när produkten eller tjänsten tillhandahålls av tandläkare eller tandtekniker.\n\nUndantaget gäller inte omsättning av glasögon eller andra synhjälpmedel även om varorna omsätts som ett led i tillhandahållandet av sjukvård.\n\nUndantaget gäller inte omsättning av varor när de omsätts av apotekare eller receptarier. Beträffande omsättning av läkemedel som lämnas ut enligt recept eller säljs till sjukhus finns särskilda bestämmelser i 23 § 2.\n\nUndantaget gäller inte vid vård av djur. Lag (2014:1492).\n\n## 5 §\n\nMed sjukvård förstås åtgärder för att medicinskt förebygga, utreda eller behandla sjukdomar, kroppsfel och skador samt vård vid barnsbörd,\n\n- om åtgärderna vidtas vid sjukhus eller någon annan inrättning som drivs av det allmänna eller, inom enskild verksamhet, vid inrättningar för sluten vård, eller\n- om åtgärderna annars vidtas av någon med särskild legitimation att utöva yrke inom sjukvården.\n\nMed sjukvård förstås även sjuktransporter som utförs med transportmedel som är särskilt inrättade för sådana transporter.\n\nMed sjukvård jämställs medicinskt betingad fotvård. Lag (1996:794).\n\n## 6 §\n\nMed tandvård förstås åtgärder för att förebygga, utreda eller behandla sjukdomar, kroppsfel och skador i munhålan.\n\n## 7 §\n\nMed social omsorg förstås offentlig eller privat verksamhet för barnomsorg, äldreomsorg, stöd och service till vissa funktionshindrade och annan jämförlig social omsorg.\n\n### Undantag för utbildning\n\n## 8 §\n\nFrån skatteplikt undantas omsättning av tjänster som utgör\n\n1. grundskole-, gymnasieskole- eller högskoleutbildning, om utbildningen anordnas av det allmänna eller en av det allmänna för utbildningen erkänd utbildningsanordnare, och\n\n2. utbildning som berättigar studerande till studiestöd enligt studiestödslagen (1999:1395) eller till\n   a) statsbidrag som administreras av Specialpedagogiska skolmyndigheten för\n\n- kortare studier om funktionshinder,\n- kortare studier på grundskole- eller gymnasienivå som är särskilt anpassade för personer med funktionshinder, och\n- studier inom kommunal vuxenutbildning som särskild utbildning, eller\n  b) statsbidrag som administreras av Sametinget för kortare studier i alfabetisering i samiska.\n\nUndantaget från skatteplikt enligt första stycket omfattar även omsättning av varor och tjänster som omsätts som ett led i utbildningen.\n\nUtbildning som tillhandahålls av utbildare mot ersättning från en uppdragsgivare som själv utser de personer som ska utbildas (uppdragsutbildning) omfattas av undantaget endast om utbildningen ingår i en av uppdragsgivaren bedriven egen utbildning enligt första stycket. Lag (2020:450).\n\n### Undantag för bank- och finansieringstjänster och för värdepappershandel\n\n## 9 §\n\nFrån skatteplikt undantas omsättning av bank- och finansieringstjänster samt sådan omsättning som utgör värdepappershandel eller därmed jämförlig verksamhet.\n\nMed bank- och finansieringstjänster avses inte notariatverksamhet, inkassotjänster, administrativa tjänster avseende factoring eller uthyrning av förvaringsutrymmen.\n\nMed värdepappershandel förstås\n\n1. omsättning och förmedling av aktier, andra andelar och fordringar, oavsett om de representeras av värdepapper eller inte, och\n2. förvaltning av värdepappersfonder enligt lagen (2004:46) om värdepappersfonder och specialfonder enligt lagen (2013:561) om förvaltare av alternativa investeringsfonder. Lag (2013:567).\n\n### Undantag för försäkringstjänster\n\n## 10 §\n\nFrån skatteplikt undantas omsättning av försäkrings- och återförsäkringstjänster, inbegripet tjänster som tillhandahålls av försäkringsmäklare eller andra förmedlare av försäkringar och som avser försäkringar eller återförsäkringar. Lag (2002:1004).\n\n### Undantag för investeringsguld\n\n## 10 a §\n\nFrån skatteplikt undantas omsättning av investeringsguld, inbegripet investeringsguld representerat av värdepapper, om omsättningen medför en äganderätt till eller en fordran på guldet.\n\nFrån skatteplikt undantas även förmedling som görs för någon annans räkning i dennes namn, om förmedlingen avser en omsättning enligt första stycket. Lag (1999:640).\n\n## 10 b §\n\nEn beskattningsbar person har rätt att bli skattskyldig för en omsättning som annars skulle ha undantagits enligt 10 a § första stycket om den beskattningsbara personen\n\n1. framställer investeringsguld eller omvandlar guld av något slag till investeringsguld och omsättningen görs till en annan beskattningsbar person, eller\n2. i sin yrkesverksamhet normalt omsätter guld för industriellt ändamål och omsättningen avser investeringsguld enligt 1 kap. 18 § första stycket 1 och görs till en annan beskattningsbar person. Lag (2013:368).\n\n## 10 c §\n\nEtt ombud har rätt att bli skattskyldigt för förmedling som annars skulle ha undantagits enligt 10 a § andra stycket om den för vars räkning förmedlingen görs är skattskyldig enligt 10 b §. Lag (1999:640).\n\n### Undantag inom kulturområdet\n\n## 11 §\n\nFrån skatteplikt undantas följande slag av omsättning:\n\n1. en utövande konstnärs framförande av ett sådant litterärt eller konstnärligt verk som omfattas av lagen (1960:729) om upphovsrätt till litterära och konstnärliga verk,\n2. tillhandahållande i biblioteksverksamhet av böcker, tidskrifter, tidningar, ljud- och bildupptagningar, reproduktioner av bildkonst samt bibliografiska upplysningar, om verksamheten bedrivs av eller fortlöpande i mer än ringa omfattning understöds av det allmänna,\n3. förvaring och tillhandahållande i arkivverksamhet av arkivhandlingar och uppgifter ur sådana handlingar, om verksamheten bedrivs av eller fortlöpande i mer än ringa omfattning understöds av det allmänna,\n4. anordnande i museiverksamhet av utställningar för allmänheten och tillhandahållande i museiverksamhet av föremål för utställningar, om verksamheten bedrivs av eller fortlöpande i mer än ringa omfattning understöds av det allmänna,\n5. av det allmänna understödd folkbildningsverksamhet som tillhandahålls av studieförbund, och\n6. kulturbildningsverksamhet som bedrivs av kommun. Lag (1996:1327).\n\n### Undantag inom idrottsområdet\n\n## 11 a §\n\nFrån skatteplikt undantas omsättning av tjänster varigenom någon bereds tillträde till idrottsligt evenemang eller tillfälle att utöva idrottslig verksamhet. Från skatteplikt undantas vidare omsättning av tjänster som har omedelbart samband med utövandet av den idrottsliga verksamheten om dessa tjänster omsätts av den som tillhandahåller den idrottsliga verksamheten.\n\nUndantaget gäller endast om tjänsterna omsätts av staten eller en kommun eller av en förening i de fall verksamheten inte anses som ekonomisk enligt 4 kap. 8 §. Lag (2013:368).\n\n### Undantag inom massmedieområdet\n\n## 13 §\n\nFrån skatteplikt undantas omsättning av periodiska medlemsblad eller periodiska personaltidningar när en sådan publikation tillhandahålls någon gratis eller mot ersättning tillhandahålls utgivaren, medlemmar eller anställda. Även införsel av en sådan publikation är undantagen från skatteplikt, om publikationen förs in till landet för att tillhandahållas på något av dessa sätt.\n\n## 14 §\n\nFrån skatteplikt undantas omsättning och införsel av periodiska organisationstidskrifter.\n\nMed en organisationstidskrift förstås en publikation\n\n- som inte är en allmän nyhetstidning, ett medlemsblad eller en personaltidning, och\n- som väsentligen framstår som ett organ för en eller flera sammanslutningar med det huvudsakliga syftet att verka för ett religiöst, nykterhetsfrämjande, politiskt, miljövårdande, idrottsligt eller försvarsfrämjande ändamål eller att företräda medlemmar med funktionshinder.\n\nSom sammanslutning med huvudsakligt syfte att verka för ett idrottsligt ändamål räknas endast sammanslutningar som är anslutna till Sveriges riksidrottsförbund eller Svenska korporationsidrottsförbundet eller som är representerade i Sveriges olympiska kommitté. Som sammanslutning med huvudsakligt syfte att verka för ett försvarsfrämjande ändamål räknas endast sådan sammanslutning som enligt därom gällande föreskrifter erhåller statligt stöd till sin verksamhet. Lag (2005:1198).\n\n## 16 §\n\nEn publikation som anges i 13 och 14 §§ anses som periodisk endast om den enligt utgivningsplanen utkommer med normalt minst fyra nummer om året. Lag (1996:1327).\n\n## 17 §\n\nUndantagen i 13 och 14 §§ omfattar även radio- och kassettidningar. Lag (1996:1327).\n\n## 18 §\n\nFrån skatteplikt undantas omsättning av program och kataloger för egen verksamhet som inte i sig medför skattskyldighet eller rätt till återbetalning av ingående skatt enligt 10 kap.9-13 §§.\n\n## 19 §\n\nFrån skatteplikt undantas omsättning av tjänster som\n\n1. avser införande eller ackvisition av annonser i periodiska medlemsblad, personaltidningar och organisationstidskrifter som anges i 13 och 14 §§, eller\n\n2. tillhandahålls en utgivare av sådana publikationer som avses i 1 på uppdrag av honom, om tjänsterna - avser framställning av publikationen, varmed förstås mångfaldigandet eller de tekniska tjänster som krävs för mångfaldigandet av publikationen, eller\n\n- avser distribution av upplagan eller någon annan åtgärd som naturligt hänger samman med framställningen.\n\nFrån skatteplikt undantas även tjänster som avser införande av annonser i sådana publikationer som anges i 18 §. Lag (2002:1004).\n\n## 20 §\n\nFrån skatteplikt undantas omsättning i verksamhet för produktion och utsändning av radio- och televisionsprogram, om verksamheten huvudsakligen finansieras genom statsanslag.\n\n### Undantag för posttjänster och frimärken\n\n## 20 a §\n\nFrån skatteplikt undantas omsättning av\n\n1. posttjänster som ingår i den samhällsomfattande posttjänsten enligt postlagen (2010:1045), till den del de tillhandahålls av någon som med stöd av samma lag är utsedd att tillhandahålla hela eller delar av denna tjänst, och\n2. frimärken som tillhandahålls till det nominella värdet och som är giltiga som betalningsmedel för posttjänster som avses i 1.\n\nOmsättning av posttjänster för vilka villkoren förhandlats individuellt omfattas dock inte av undantaget i första stycket 1.Lag (2016:91).\n\n### Undantag för fartyg och luftfartyg\n\n## 21 §\n\nFrån skatteplikt undantas omsättning av\n\n1. luftfartyg som ska användas av flygbolag som huvudsakligen bedriver internationell flygtrafik mot betalning,\n2. tjänster, såsom ombyggnad, reparation, underhåll, befraktning och uthyrning som avser sådana luftfartyg,\n\n3. delar, tillbehör eller utrustning till sådana luftfartyg, när varan\n\n- säljs eller hyrs ut till den som äger luftfartyget eller den som varaktigt nyttjar luftfartyget enligt avtal med ägaren, eller\n- förs in till landet för ägarens eller nyttjanderättshavarens räkning, och\n\n4. tjänster som avser delar, tillbehör eller utrustning som anges i 3. Lag (2017:1196).\n\n## 21 a §\n\nFrån skatteplikt undantas omsättning av\n\n1. fartyg som används på öppna havet och fraktar passagerare mot betalning eller används för handels-, industri- eller fiskeriverksamhet,\n2. fartyg som används för sjöräddning eller assistans eller för kustfiske,\n3. utrustning, inklusive fiskeriutrustning, som utgör en del av eller används i ett fartyg som anges i 1 eller 2,\n4. varor för förbrukning ombord på fartyg som anges i 1,\n\n5. varor för försäljning ombord på fartyg som anges i 1\n   a) i andra fall än som avses i 5 kap. 2 b §,\n   b) i de fall som avses i 5 kap. 2 b §, om varorna är sådana livsmedel som anges i artikel 2 i Europaparlamentets och rådets förordning (EG) nr 178/2002 av den 28 januari 2002 om allmänna principer och krav för livsmedelslagstiftning, om inrättande av Europeiska myndigheten för livsmedelssäkerhet och om förfaranden i frågor som gäller livsmedelssäkerhet, och\n6. varor för förbrukning eller försäljning ombord på fartyg som anges i 2, dock inte fartygsproviant för fartyg som används för kustfiske.\n\nI fråga om punktskattepliktiga varor gäller första stycket 4 och 5 a endast om omsättningen uppfyller villkoren för proviantering i 7–9 §§ lagen (1999:446) om proviantering av fartyg och luftfartyg. Första stycket 5 b gäller inte i fråga om punktskattepliktiga varor.\n\nOmsättning av varor för försäljning ombord på fartyg på linjer mellan Sverige och Norge eller mellan Sverige och Åland undantas från skatteplikt enligt första stycket 5 endast om omsättningen inte strider mot 5 och 6 §§ lagen om proviantering av fartyg och luftfartyg. Lag (2017:1196).\n\n## 21 b §\n\nFrån skatteplikt undantas omsättning av\n\n1. tjänster i form av ombyggnad, reparation, underhåll, befraktning och uthyrning av fartyg som anges i 21 a § första stycket 1 eller 2,\n2. tjänster i form av uthyrning, reparation och underhåll av sådan utrustning som avses i 21 a § första stycket 3,\n3. andra tjänster än de som avses i 1 eller 2 för att täcka direkta behov för de fartyg som anges i 21 a § första stycket 1 eller 2 och deras laster. Lag (2017:1196).\n\n## 22 §\n\nFrån skatteplikt undantas omsättning av tjänster som tillhandahålls av sådana mäklare och andra förmedlare som handlar för någon annans räkning i dennes namn, om tjänsten avser en sådan omsättning som anges i 21, 21 a eller 21 b §. Lag (2017:1196).\n\n### Undantag för vissa andra varor och tjänster\n\n## 23 §\n\nFrån skatteplikt undantas omsättning av följande slag av varor och tjänster:\n\n1. sedlar och mynt som är lagligt betalningsmedel, med undantag av samlarföremål, det vill säga guld-, silver- eller andra metallmynt eller sedlar som normalt inte används som lagligt betalningsmedel eller som är av numismatiskt intresse,\n2. läkemedel som lämnas ut enligt recept eller säljs till sjukhus eller förs in i landet i anslutning till sådan utlämning eller försäljning,\n3. modersmjölk, blod eller organ från människor,\n4. flygbensin och flygfotogen,\n5. lotterier, inräknat vadhållning och andra former av spel,\n6. tjänster som avser gravöppning eller gravskötsel på allmän begravningsplats när tjänsten tillhandahålls av huvudmannen för eller innehavaren av begravningsplatsen, och\n7. guld som levereras till Sveriges riksbank. Lag (2007:1376).\n\n### Undantag för vissa interna tjänster\n\n## 23 a §\n\nFrån skatteplikt undantas omsättning av tjänster som tillhandahålls inom fristående grupper av fysiska eller juridiska personer, om\n\n- verksamheten i övrigt inte medför skattskyldighet hos gruppen eller hos de fysiska eller juridiska personerna,\n- tjänsterna är direkt nödvändiga för utövandet av verksamheten, och\n- ersättningen för tjänsterna exakt motsvarar den fysiska eller juridiska personens andel av de gemensamma kostnaderna för tjänsternas tillhandahållande.\n\nUndantaget avser endast sådana tjänster som normalt inte tillhandahålls av någon annan utanför gruppen. Lag (1998:346).\n\n### Undantag för överlåtelse av vissa tillgångar\n\n## 24 §\n\nFrån skatteplikt undantas överlåtelse av andra tillgångar än omsättningstillgångar, om\n\n1. den som överlåter tillgången kan visa att han varken har haft någon rätt till avdrag för eller återbetalning enligt 10 kap.9–13 §§ av ingående skatt vid förvärvet av tillgången eller vid mera betydande förvärv av varor eller tjänster som tillförts tillgången, eller\n2. överföring av tillgången från en verksamhet till en annan verksamhet har medfört skattskyldighet enligt 2 kap. 2 § 2.\n\nVid tillämpning av första stycket anses som omsättningstillgångar inte tillgångar som är avsedda att förbrukas i en verksamhet.\n\nUndantaget från skatteplikt enligt denna paragraf omfattar inte försäkringsföretags överlåtelse av tillgångar som övertagits i samband med skadereglering och inte heller finansieringsföretags överlåtelse av tillgångar som företaget har återtagit med stöd av ett av företaget övertaget köpeavtal. Undantaget gäller inte heller om den omsättning genom vilken den skattskyldige förvärvat varan eller, om varan förts in till landet, det unionsinterna förvärvet eller importen undantagits från skatteplikt enligt 3 kap.21 eller 21 a §. Lag (2017:1196).\n\n### Undantag för överlåtelse av motorfordon till utländska beskickningar m.fl.\n\n## 26 a §\n\nFrån skatteplikt undantas omsättning av motorfordon, om köparen är någon som har rätt till återbetalning av ingående skatt\n\n1. enligt 10 kap. 6 §, eller\n2. enligt 10 kap. 7 §, om fordonet är avsett för köparens personliga bruk.\n\nUndantaget enligt första stycket gäller endast om köparen till säljaren överlämnar ett intyg som visar att de förutsättningar som anges i första stycket är uppfyllda. Intyget skall vara utfärdat av Utrikesdepartementet. Säljaren skall till Skatteverket ge in kopia av intyget samt kopia av fakturan. Lag (2003:1134).\n\n## 26 b §\n\nHar motorfordon förvärvats genom en omsättning som undantagits från skatteplikt enligt 26 a § och överlåter köparen fordonet tidigare än två år efter förvärvet, ska denne till staten betala ett belopp som motsvarar den skatt som han skulle ha fått betala, om han hade varit skattskyldig för omsättningen. Beloppet ska dock inte överstiga den skatt som skulle ha betalats vid överlåtarens förvärv, om 26 a § inte hade tillämpats. Om det inte betalas någon ersättning vid överlåtelsen av motorfordonet eller om ersättningen väsentligen understiger marknadsvärdet, ska beloppet beräknas med utgångspunkt från marknadsvärdet.\n\nFörsta stycket tillämpas även om motorfordonet förvärvats genom ett unionsinternt förvärv som undantagits från skatteplikt.\n\nVid beräkning av belopp som enligt första stycket ska betalas till staten tillämpas 7 kap.\n\nFörsta stycket ska inte tillämpas, om fordonet överlåts på grund av att ägaren avlidit. Inte heller ska första stycket tillämpas, om den till vilken fordonet överlåts kan förvärva motorfordon genom en omsättning som undantas från skatteplikt enligt 26 a §. Sker sådan överlåtelse, ska den som förvärvar fordonet anses ha förvärvat detta genom en omsättning som undantas från skatteplikt enligt 26 a §.\n\nÖverlåts fordonet på grund av att ägaren fått förflyttning från Sverige, ska första stycket inte tillämpas om ägaren innehaft fordonet minst sex månader. Lag (2011:283).\n\n## 26 c §\n\nBelopp som avses i 26 b § skall betalas genom insättning på ett särskilt konto. Betalning skall ske senast 35 dagar efter överlåtelsen av motorfordonet. Lag (1996:1320).\n\n### Undantag för uttag av varor och tjänster\n\n## 29 §\n\nFrån skatteplikt undantas kommunernas uttag av varor och tjänster för eget behov. Från skatteplikt undantas även statens uttag av tjänster som avses i 2 kap. 8 §.\n\nUndantaget omfattar inte statens eller en kommuns uttag av tjänster när det gäller arbeten på stadigvarande bostad i sådana fall som avses i 2 kap. 8 §. Undantaget gäller dock för kommunernas uttag av tjänster i fråga om sådana boendeformer som avses i 4 § lagen (2005:807) om ersättning för viss mervärdesskatt för kommuner, regioner, kommunalförbund och samordningsförbund. Lag (2019:886).\n\n### Undantag för viss import\n\n## 30 §\n\nFrån skatteplikt undantas sådan import som medför frihet från skatt enligt lagen (1994:1551) om frihet från skatt vid import, m.m.\n\nFrån skatteplikt undantas även import av en vara som efter importen ska omsättas till ett annat EU-land enligt\n\n1. 30 a § första stycket 2 eller 3 eller 30 c §, eller\n\n2. 30 a § första stycket 1 eller andra stycket, om importören\n   a) har angivit sitt registreringsnummer till mervärdesskatt i Sverige,\n   b) har angivit sitt registreringsnummer till mervärdesskatt i det EU-land dit varan överförs eller det registreringsnummer till mervärdesskatt som köparen av varan har i ett annat EU- land än Sverige, och\n   c) har, innan varan övergår till fri omsättning, inkommit till Tullverket med bevisning om att varan är avsedd att transporteras eller sändas till ett annat EU-land.\n\nRegistreringsnumren i andra stycket 2 a och b ska anges vid den tidpunkt då skattskyldighet skulle ha inträtt enligt 1 kap. 5 § om importen hade varit skattepliktig.\n\nAndra stycket 2 c gäller endast om Tullverket begär sådan bevisning.\n\nFrån skatteplikt undantas även import av\n\n1. gas som\n   a) transporteras genom ett naturgassystem eller genom ett gasnät som är anslutet till ett sådant system, eller\n   b) förs över från ett fartyg som transporterar gas till ett naturgassystem eller till ett rörledningsnät uppströms,\n2. el, eller\n3. värme eller kyla genom ett nät för värme eller kyla.\n\nFrån skatteplikt undantas import som görs av en beskattningsbar person eller en representant som har ett identifieringsbeslut och identifieringsnummer enligt 4 e och 7 §§ lagen (2011:1245) om särskilda ordningar för mervärdesskatt för distansförsäljning av varor och för tjänster eller enligt motsvarande bestämmelser i ett annat EU- land, om identifieringsnumret har tillhandahållits Tullverket senast i samband med inlämnandet av tulldeklarationen.\n\nFrån skatteplikt undantas import av en vara som görs av väpnade styrkor tillhörande ett annat EU-land för användning av dessa styrkor eller av den civilpersonal som följer med dem, eller för försörjning av deras mässar eller marketenterier, om dessa styrkor deltar i en försvarsinsats för att genomföra en unionsverksamhet inom ramen för den gemensamma säkerhets- och försvarspolitiken. Lag (2022:160).\n\n### Vissa undantag för omsättning till och förvärv från andra EU- länder\n\n## 30 a §\n\nFrån skatteplikt undantas omsättning av varor som transporteras av säljaren eller köparen eller för någonderas räkning från Sverige till ett annat EU-land, om\n\n1. följande villkor är uppfyllda:\n   a) köparen är en beskattningsbar person eller en juridisk person som inte är en beskattningsbar person och agerar i denna egenskap i ett annat EU-land,\n   b) köparen är registrerad till mervärdesskatt i ett annat EU- land och har meddelat säljaren sitt registreringsnummer, och\n   c) säljaren har fullgjort sin skyldighet att lämna korrekta uppgifter om leveransen i en periodisk sammanställning enligt 35 kap.skatteförfarandelagen (2011:1244) eller kan förklara på ett tillfredsställande sätt varför så inte skett,\n2. varorna är punktskattepliktiga och förvärvaren inte är en privatperson, eller\n3. varorna är nya transportmedel.\n\nFrån skatteplikt undantas en sådan överföring av vara som avses i 2 kap. 1 § andra stycket om förhållandena är sådana som anges i första stycket 1-3 i den här paragrafen.\n\nOm köparen antingen är en juridisk person som inte är en beskattningsbar person eller en beskattningsbar person som saknar rätt till avdrag eller återbetalning motsvarande den i 10 kap. 1-4 a eller 10 kap.9-13 §§, gäller undantaget i första stycket 1 enbart om\n\n1. det sammanlagda beloppet för köparens unionsinterna förvärv i det EU-land som förvärvet äger rum i under kalenderåret eller det närmast föregående kalenderåret överstiger det belopp som landet har fastställt enligt artikel 3.2 i rådets direktiv 2006/112/EG, eller\n2. köparen har utnyttjat en möjlighet att bli skattskyldig för sina förvärv i det EU-land som avses i 1.\n\nDetsamma gäller om köparen är en beskattningsbar person vars förvärv avser en jordbruks-, skogsbruks- eller fiskeverksamhet som omfattas av schablonbeskattning enligt bestämmelserna i avdelning XII kapitel 2 i rådets direktiv 2006/112/EG.\n\nUndantaget från skatteplikt i första stycket 1 eller 2 gäller inte om säljaren omfattas av skattebefrielse enligt 9 d kap.Lag (2019:789).\n\n## 30 b §\n\nFrån skatteplikt undantas unionsinterna förvärv enligt 2 a kap. 2 § 1 av varor som görs av en utländsk beskattningsbar person, om\n\n1. den utländska beskattningsbara personen är registrerad till mervärdesskatt i ett annat EU-land,\n2. förvärvet görs för en efterföljande omsättning här i landet,\n3. varan sänds eller transporteras direkt till Sverige från ett annat EU-land än det där den utländska beskattningsbara personen är registrerad till mervärdesskatt, och\n4. den till vilken den efterföljande omsättningen görs är en beskattningsbar person eller en juridisk person som inte är en beskattningsbar person, som är registrerad till mervärdesskatt här och som är skattskyldig för omsättningen enligt 1 kap. 2 § första stycket 4.Lag (2013:368).\n\n## 30 c §\n\nFrån skatteplikt undantas omsättning av varor som transporteras av säljaren eller köparen eller för någonderas räkning från Sverige till ett annat EU-land, om\n\n1. köparen är en beskickning eller ett konsulat i ett annat EU-land eller en medlem av den diplomatiska personalen vid en sådan beskickning eller ett sådant konsulat,\n\n2. köparen är ett i ett annat EU-land beläget kontor eller anläggning som tillhör\n\n- Europeiska unionen,\n- Europeiska atomenergigemenskapen,\n- Europeiska centralbanken,\n- Europeiska investeringsbanken, eller\n- ett organ som har inrättats av unionen eller atomenergigemenskapen och för vilket protokollet (nr 7) om Europeiska unionens immunitet och privilegier gäller, eller\n\n3. köparen är\n   a) ett i ett annat EU-land beläget kontor eller anläggning som tillhör en annan internationell organisation än som anges i 2,\n   b) en medlemsstats ombud vid en sådan organisation,\n   c) en person med tjänst hos en sådan organisation, eller\n   d) en person med uppdrag hos en sådan organisation.\n\nFrån skatteplikt undantas omsättning av tjänster som tillhandahålls\n\n1. ett i ett annat EU-land beläget kontor eller anläggning som avses i\n   a) första stycket 2, eller\n   b) första stycket 3, eller\n\n2. en person som i en sådan organisation som avses i första stycket 3\n   a) är en medlemsstats ombud,\n   b) har en tjänst, eller\n   c) har uppdrag.\n\nEn omsättning är undantagen från skatteplikt enligt första eller andra stycket endast i den omfattning som frihet från mervärdesskatt medges en motsvarande omsättning i det EU-land som följer av samma bestämmelser och förvärvet görs av en sådan köpare som anges i dem.\n\nEn omsättning är undantagen från skatteplikt enligt första stycket 2 och andra stycket 1 a endast i den omfattning skattefriheten inte leder till att konkurrensen snedvrids. Lag (2015:888).\n\n## 30 d §\n\nFrån skatteplikt undantas unionsinterna förvärv som görs av utländska beskattningsbara personer om det skulle finnas rätt till återbetalning enligt 10 kap.1-3 och 13-13 b §§ av hela skatten med anledning av förvärvet.\n\nFrån skatteplikt undantas även unionsinterna förvärv som görs under sådana förutsättningar att det skulle finnas rätt till återbetalning enligt 10 kap. 6, 6 a eller 7 §.\n\nOm villkoren för undantaget i andra stycket upphör att vara uppfyllda för att det inte längre skulle finnas rätt till återbetalning enligt 10 kap. 6 a §, ska Europeiska kommissionen eller den byrå eller det organ som har förvärvat varorna underrätta Skatteverket. Det unionsinterna förvärvet ska då beskattas enligt de förutsättningar som gällde vid den tidpunkt då villkoren upphörde att vara uppfyllda. Lag (2021:1185).\n\n## 30 e §\n\nFrån skatteplikt undantas omsättning av tjänster som avser varutransporter till eller från Azorerna eller Madeira eller mellan dessa öar. Lag (1994:1798).\n\n## 30 f §\n\nFrån skatteplikt undantas unionsinterna förvärv av begagnade varor, konstverk, samlarföremål och antikviteter, om varorna har sålts av en beskattningsbar återförsäljare som agerar i denna egenskap och omsättningen har beskattats i det EU-land där transporten till Sverige påbörjats enligt bestämmelser som motsvarar artiklarna 312–325 i rådets direktiv 2006/112/EG. Lag (2013:368).\n\n## 30 g §\n\nFrån skatteplikt undantas omsättning av transporttjänster och därtill anslutna tjänster i samband med distribution av brev eller paket, om tjänsterna tillhandahålls mellan ett utländskt postbefordringsföretag och någon som är utsedd att tillhandahålla hela eller delar av den samhällsomfattande posttjänsten enligt postlagen (2010:1045). Lag (2016:91).\n\n## 31 §\n\nFrån skatteplikt undantas omsättning av varor och tjänster som har ett annat EU-land som destinationsland, om\n\n- omsättningen är avsedd för väpnade styrkor tillhörande någon annan stat som är part i Nato än destinationslandet,\n- varorna eller tjänsterna ska användas av dessa styrkor eller av den civilpersonal som åtföljer dem eller användas för försörjning av deras mässar eller marketenterier, och\n- styrkorna deltar i de gemensamma försvarsansträngningarna.\n\nSkattefriheten enligt första stycket medges i den omfattning som frihet från mervärdesskatt medges i destinationslandet för motsvarande omsättning. Lag (2011:283).\n\n## 31 a §\n\nFrån skatteplikt undantas omsättning av varor och tjänster till Förenade kungariket Storbritannien och Nordirlands väpnade styrkor stationerade på ön Cypern i enlighet med Fördraget om upprättandet av Republiken Cypern av den 16 augusti 1960, om\n\n- omsättningen är avsedd för dessa styrkor, och\n- varorna eller tjänsterna skall användas av dessa styrkor eller av den civilpersonal som åtföljer dem eller användas för försörjning av deras mässar eller marketenterier. Lag (2004:1155).\n\n## 31 b §\n\nFrån skatteplikt undantas omsättning av varor och tjänster som har ett annat EU-land som destinationsland, om\n\n- omsättningen är avsedd för väpnade styrkor tillhörande ett annat EU-land än destinationslandet,\n- varorna eller tjänsterna är avsedda att användas av dessa styrkor eller av den civilpersonal som följer med dem, eller för försörjning av deras mässar eller marketenterier, och\n- styrkorna deltar i en försvarsinsats för att genomföra en unionsverksamhet inom ramen för den gemensamma säkerhets- och försvarspolitiken.\n\nSkattefrihet enligt första stycket medges i den omfattning som frihet från mervärdesskatt medges i destinationslandet för motsvarande omsättning. Lag (2022:160).\n\n## 31 c §\n\nFrån skatteplikt undantas omsättning av varor till Europeiska kommissionen eller en byrå eller ett organ som har inrättats enligt unionsrätten, om\n\n1. varorna sänds eller transporteras från Sverige till ett annat EU-land,\n2. Europeiska kommissionen, byrån eller organet förvärvar varorna för att utföra uppgifter som har tilldelats enligt unionsrätten i syfte att hantera covid-19-pandemin, och\n3. Europeiska kommissionen, byrån eller organet inte säljer de förvärvade varorna vidare, vare sig direkt eller vid en senare tidpunkt.\n\nOm villkoren för undantaget i första stycket upphör att vara uppfyllda, ska Europeiska kommissionen, byrån eller organet som har förvärvat varorna underrätta Skatteverket. Omsättningen av varorna till Europeiska kommissionen, byrån eller organet ska då beskattas enligt de förutsättningar som gällde vid den tidpunkt då villkoren för undantaget upphörde att vara uppfyllda. Lag (2021:1185).\n\n### Undantag för viss omsättning i samband med import\n\n## 32 §\n\nUtgör ersättningen för en tjänst en sådan bikostnad som enligt 7 kap. 8 § tredje stycket ska ingå i beskattningsunderlaget för import, är omsättningen av tjänsten undantagen från skatteplikt. Detsamma gäller om en sådan bikostnad ska ingå i beskattningsunderlaget vid införsel till ett annat EU-land i enlighet med det landets tillämpning av artikel 86.1 b i rådets direktiv 2006/112/EG. Lag (2021:1148).\n\n### Undantag för omsättning till beskattningsbara personer som använder ett elektroniskt gränssnitt\n\n## 33 §\n\nFrån skatteplikt undantas omsättning av en vara till en beskattningsbar person som anses ha förvärvat och omsatt varan i enlighet med 6 kap. 10 §. Lag (2020:1170).\n\n# 5 kap. Omsättningsland\n\n## 1 §\n\nI 2-18 §§ och 9 b kap. 4 § första stycket finns bestämmelser om i vilka fall en omsättning ska anses som en omsättning inom landet. All annan omsättning anses som omsättning utomlands.\n\nI 3 a och 19 §§ finns bestämmelser om i vilka fall en omsättning som enligt någon av 2-18 §§ eller 9 b kap. 4 § första stycket anses som en omsättning inom landet ändå ska anses som en omsättning utomlands.\n\nOmsättning på fartyg eller luftfartyg i utrikes trafik i andra fall än som anges i 2 b § räknas aldrig som omsättning inom landet.\n\nOm en beskattningsbar person anses ha förvärvat och omsatt en vara enligt 6 kap. 9 § ska omsättningen till den beskattningsbara personen aldrig räknas som en omsättning inom landet. Lag (2020:1170).\n\n### Omsättning inom landet av varor\n\n## 2 §\n\nEn vara som enligt avtalet mellan säljare och köpare ska transporteras till köparen är omsatt inom landet, om\n\n1. varan finns här i landet då säljaren, köparen eller någon annan påbörjar transporten till köparen, under förutsättning att\n   a) annat inte följer av 2 a §, eller\n   b) transporten inte ska hänföras till en annan omsättning enligt 2 e §,\n2. varan inte finns här i landet då transporten påbörjas men varan monteras eller installeras här av säljaren eller för dennes räkning,\n3. varan inte finns här i landet då transporten påbörjas men varan importeras till landet från en plats utanför EU av den som är skattskyldig enligt 1 kap. 2 § första stycket 6 för att omsättas, under förutsättning att annat inte följer av 5 kap. 2 f § tredje stycket, eller\n4. varan inte finns här i landet när transporten påbörjas men däremot när försändningen eller transporten till köparen avslutas och det är fråga om unionsintern distansförsäljning av varor enligt 2 kap. 1 j §.\n\nEn vara är dock inte omsatt inom landet enligt första stycket 4 om den är omsatt i ett annat EU-land enligt bestämmelser som i det landet motsvarar artikel 59c.1 i rådets direktiv 2006/112/EG. Lag (2020:1170).\n\n## 2 a §\n\nÄven om en vara finns här i landet på det sätt som anges i 2 § första stycket 1 ska varan inte anses omsatt inom landet, om\n\n1. det är fråga om unionsintern distansförsäljning av varor och försändningen eller transporten av varan avslutas i ett annat EU-land, under förutsättning att annat inte följer av 20 §, eller\n2. varan transporteras av säljaren, köparen eller någon annan och ska installeras eller monteras i ett annat EU-land av säljaren eller för dennes räkning. Lag (2020:1170).\n\n## 2 b §\n\nEn vara som omsätts på fartyg, luftfartyg eller tåg under den del av en persontransport som genomförs inom EU, ska anses omsatt i Sverige om avgångsorten är belägen i Sverige.\n\nMed del av en persontransport som genomförs inom EU avses den del av en persontransport som utan uppehåll utanför EU utförs mellan avgångsorten och ankomstorten.\n\nMed avgångsorten avses den första orten för påstigning av passagerare inom EU. Detta gäller även om en del av transporten dessförinnan utförts utanför EU.\n\nMed ankomstorten avses den sista orten för avstigning av passagerare inom EU för passagerare som stigit på inom EU. Detta gäller även om en del av transporten därefter utförs utanför EU.\n\nFör en resa tur och retur gäller att återresan ska anses som en fristående transport. Lag (2011:283).\n\n## 2 c §\n\nOmsättning av gas genom ett naturgassystem som är beläget inom unionens territorium eller genom ett gasnät som är anslutet till ett sådant system, till en beskattningsbar återförsäljare ska anses som en omsättning inom landet, om återförsäljaren antingen har sätet för sin ekonomiska verksamhet i Sverige eller har ett fast etableringsställe här för vilket varan levereras. Om återförsäljaren varken här eller utomlands har ett sådant säte eller fast etableringsställe, är varan omsatt inom landet, om återförsäljaren är bosatt eller stadigvarande vistas i Sverige.\n\nEn vara är dock inte omsatt inom landet om den levereras till ett fast etableringsställe som återförsäljaren har utomlands.\n\nFörsta och andra styckena gäller även omsättning av\n\n1. el, eller\n2. värme eller kyla genom ett nät för värme eller kyla.\n\nMed en beskattningsbar återförsäljare förstås i denna paragraf en beskattningsbar person vars huvudsakliga verksamhet när det gäller köp av gas, el, värme eller kyla består i att sälja sådana varor vidare och vars egen konsumtion av dessa varor är försumbar. Lag (2013:368).\n\n## 2 d §\n\nOmsättning av gas genom ett naturgassystem som är beläget inom unionens territorium eller genom ett gasnät som är anslutet till ett sådant system, ska anses som en omsättning inom landet, om köparens faktiska användning och förbrukning av varan äger rum i Sverige och omsättningen inte omfattas av 2 c §.\n\nOm varan inte helt förbrukas av köparen, ska den återstående delen av varan ändå anses ha använts och förbrukats i Sverige, om köparen antingen har sätet för sin ekonomiska verksamhet i Sverige eller har ett fast etableringsställe här för vilket varan levereras. Om köparen varken här eller utomlands har ett sådant säte eller fast etableringsställe, ska varan anses omsatt i Sverige, om köparen är bosatt eller stadigvarande vistas här i landet.\n\nEn vara är dock inte omsatt inom landet om den levereras till ett fast etableringsställe som köparen har utomlands.\n\nFörsta-tredje styckena gäller även omsättning av\n\n1. el, eller\n2. värme eller kyla genom ett nät för värme eller kyla. Lag (2011:283).\n\n## 2 e §\n\nVid flera på varandra följande omsättningar av samma vara, där varan transporteras från ett EU-land till ett annat EU-land direkt från den första leverantören till den sista köparen i kedjan, ska transporten hänföras till den omsättning som görs till den leverantör, annan än den första, som transporterar eller låter transportera varan (mellanman).\n\nTransporten ska dock hänföras till den omsättning som görs av mellanmannen om denne till sin leverantör har meddelat sitt registreringsnummer för mervärdesskatt i det EU-land som varan transporterades från.\n\nFörsta och andra styckena gäller dock inte för omsättningar som omfattas av 6 kap. 10 §. Lag (2020:1170).\n\n## 2 f §\n\nVid distansförsäljning av varor importerade från ett land utanför EU till Sverige är varan omsatt inom landet om försändningen eller transporten till köparen avslutas här och mervärdesskatt för varorna ska redovisas enligt lagen (2011:1245) om särskilda ordningar för mervärdesskatt för distansförsäljning av varor och för tjänster eller enligt bestämmelser som i ett annat EU-land motsvarar den särskilda ordningen i artiklarna 369l-369x i rådets direktiv 2006/112/EG.\n\nVid distansförsäljning av varor importerade från ett land utanför EU till ett annat EU-land är varan omsatt inom landet om försändningen eller transporten till köparen avslutas här.\n\nVid distansförsäljning av varor importerade från ett land utanför EU till Sverige är dock varan omsatt utomlands om försändningen eller transporten till köparen avslutas i ett annat EU-land. Lag (2020:1170).\n\n## 2 g §\n\nOm en beskattningsbar person anses ha förvärvat och omsatt en vara enligt 6 kap.9 eller 10 § ska transporten av varan hänföras till omsättningen. Lag (2020:1170).\n\n## 3 §\n\nI annat fall än som avses i 2-2 f §§ är varan omsatt inom landet, om den finns här då den tas om hand av köparen. Lag (2020:1170).\n\n### Undantag från 2, 2 a, 2 b eller 3 §\n\n## 3 a §\n\nEn omsättning enligt 2, 2 a, 2 b eller 3 § av en vara anses som en omsättning utomlands, om\n\n1. säljaren levererar varan till en plats utanför EU,\n2. direkt utförsel av varan till en plats utanför EU ombesörjs av en speditör eller fraktförare,\n3. en utländsk beskattningsbar person förvärvar varan för sin verksamhet i utlandet och hämtar den för direkt utförsel till en plats utanför EU,\n4. varan levereras till ett luftfartyg i utrikes trafik för bruk ombord på ett sådant luftfartyg eller för sådan omsättning som anges i 1 § tredje stycket,\n   4a. varan levereras till ett luftfartyg i de fall som avses i 2 b § för försäljning ombord och avser sådana livsmedel som anges i artikel 2 i Europaparlamentets och rådets förordning (EG) nr 178/2002 av den 28 januari 2002 om allmänna principer och krav för livsmedelslagstiftning, om inrättande av Europeiska myndigheten för livsmedelssäkerhet och om förfaranden i frågor som gäller livsmedelssäkerhet, dock inte punktskattepliktiga varor,\n5. varan omsätts på fartyg eller luftfartyg i de fall som avses i 2 b § för konsumtion ombord,\n6. det är fråga om en leverans av obeskattade unionsvaror av de slag som avses i 4 § andra stycket lagen (1999:445) om exportbutiker och varorna är avsedda för försäljning i en sådan butik,\n   6a. det är fråga om en sådan försäljning som avses i 4 § första stycket lagen om exportbutiker,\n\n7. varan är en personbil eller motorcykel som vid leveransen är tillfälligt registrerad enligt 17 § första stycket 1 lagen (2019:370) om fordons registrering och användning, under förutsättning att\n   a) fordonet levereras till en fysisk person som är bosatt eller stadigvarande vistas i ett annat land än ett EU-land, och\n   b) säljaren kan visa att fordonet varaktigt förts till en plats utanför EU före utgången av den sjätte månaden efter den månad då fordonet levererades, eller\n\n8. varan levereras här i landet till en fysisk person som är bosatt eller stadigvarande vistas i ett annat land än ett EU- land, under förutsättning att\n   a) ersättningen utgör minst 200 kronor, och\n   b) säljaren kan visa att köparen har medfört varan vid resa till en plats utanför EU före utgången av tredje månaden efter den månad under vilken leveransen av varan gjordes.\n\nVid leverans av en vara inom landet till en fysisk person som är bosatt i Norge eller på Åland anses omsättningen som en omsättning utomlands endast om\n\n1. leveransen avser en vara eller en grupp av varor som normalt utgör en helhet och ersättningen utgör minst 1 000 kronor efter avdrag för skatt enligt denna lag som hänför sig till ersättningen, och\n2. säljaren kan visa att köparen i nära anslutning till leveransen fört in varan eller varorna till Norge eller till Åland och därvid enligt tullräkning eller liknande handling betalat skatt motsvarande skatt enligt denna lag.\n\nEn leverans som avses i första stycket 4 av punktskattepliktiga varor ska anses som en omsättning utomlands endast om leveransen uppfyller de villkor som gäller för proviantering i 7-9 §§ lagen (1999:446) om proviantering av fartyg och luftfartyg. Lag (2019:373).\n\n### Omsättning inom landet av tjänster\n\n### Beskattningsbar person\n\n## 4 §\n\nVid tillämpningen av 5–19 §§ ska en\n\n1. beskattningsbar person som även bedriver verksamhet som inte innefattar sådan omsättning som anges i 2 kap. eller som inte är ekonomisk enligt 4 kap., anses vara en beskattningsbar person för alla tjänster som denne förvärvar,\n2. juridisk person som inte är en beskattningsbar person men som är registrerad till mervärdesskatt eller som skulle ha varit en beskattningsbar person om inte 4 kap. 8 § varit tillämplig, anses vara en beskattningsbar person. Lag (2013:368).\n\n### Huvudregler\n\n## 5 §\n\nEn tjänst som tillhandahålls en beskattningsbar person som agerar i denna egenskap är omsatt inom landet, om den beskattningsbara personen antingen har sätet för sin ekonomiska verksamhet i Sverige eller har ett fast etableringsställe här och tjänsten tillhandahålls detta. Om den beskattningsbara personen varken här eller utomlands har ett sådant säte eller fast etableringsställe är tjänsten omsatt inom landet, om den beskattningsbara personen är bosatt eller stadigvarande vistas i Sverige.\n\nEn tjänst är dock inte omsatt inom landet om den tillhandahålls ett fast etableringsställe som den beskattningsbara personen har utomlands. Lag (2013:368).\n\n## 6 §\n\nEn tjänst som tillhandahålls någon som inte är en beskattningsbar person är omsatt inom landet, om den som tillhandahåller tjänsten antingen har sätet för sin ekonomiska verksamhet i Sverige eller har ett fast etableringsställe här från vilket tjänsten tillhandahålls. Om den som tillhandahåller tjänsten varken här eller utomlands har ett sådant säte eller fast etableringsställe är tjänsten omsatt inom landet, om denne är bosatt eller stadigvarande vistas i Sverige.\n\nEn tjänst är dock inte omsatt inom landet om den tillhandahålls från ett fast etableringsställe utomlands. Lag (2013:368).\n\n### Undantag från huvudreglerna\n\n## 7 §\n\nEn förmedlingstjänst som tillhandahålls någon som inte är en beskattningsbar person är omsatt inom landet, om\n\n1.  tjänsten utförs för någon annans räkning i dennes namn, och\n\n2.  den omsättning som tjänsten avser görs inom landet enligt denna lag. Lag (2013:368).\n\n## 8 §\n\nEn tjänst med anknytning till en fastighet är omsatt inom landet, om fastigheten är belägen i Sverige. Lag (2009:1333).\n\n## 9 §\n\nEn varu- eller persontransporttjänst är omsatt inom landet om transporten inte till någon del genomförs i ett annat land, om inte annat följer av andra stycket eller 10 §.\n\nFörsta stycket gäller inte en varutransporttjänst som tillhandahålls en beskattningsbar person. Lag (2016:91).\n\n## 10 §\n\nEn unionsintern varutransporttjänst som tillhandahålls någon som inte är en beskattningsbar person är omsatt inom landet, om avgångsorten är belägen i Sverige.\n\nMed unionsintern varutransport avses en transport av varor där avgångs- och ankomstorterna är belägna i två skilda EU-länder.\n\nMed avgångsorten avses den ort där transporten av varorna faktiskt inleds, utan hänsyn till det avstånd som tillryggalagts till den plats där varorna befinner sig.\n\nMed ankomstorten avses den ort där transporten av varorna faktiskt avslutas. Lag (2013:368).\n\n## 11 §\n\nTjänster som tillhandahålls någon som inte är en beskattningsbar person i samband med en aktivitet som anges i andra stycket är omsatta inom landet, om aktiviteten faktiskt äger rum i Sverige. Detsamma gäller till dessa tjänster underordnade tjänster och tjänster som tillhandahålls av den som organiserar aktiviteten.\n\nFörsta stycket gäller en aktivitet som är\n\n1.  kulturell,\n\n2.  konstnärlig,\n\n3.  idrottslig,\n\n4.  vetenskaplig,\n\n5.  pedagogisk,\n\n6.  av underhållningskaraktär, eller\n\n7.  liknande dem som anges i 1–6, såsom mässor och utställningar. Lag (2013:368).\n\n## 11 a §\n\nEn tjänst i form av tillträde till evenemang som anges i andra stycket och tillhandahålls en beskattningsbar person är omsatt inom landet, om evenemanget faktiskt äger rum i Sverige. Detsamma gäller tjänster i anknytning till tillträdet.\n\nFörsta stycket gäller evenemang som är\n\n1.  kulturella,\n\n2.  konstnärliga,\n\n3.  idrottsliga,\n\n4.  vetenskapliga,\n\n5.  pedagogiska,\n\n6.  av underhållningskaraktär, eller\n\n7.  liknande dem som anges i 1–6, såsom mässor och utställningar. Lag (2013:368).\n\n## 12 §\n\nTjänster med anknytning till transportverksamhet såsom lastning, lossning, godshantering och liknande tjänster som tillhandahålls någon som inte är en beskattningsbar person, är omsatta inom landet om de fysiskt utförs i Sverige. Detsamma gäller tjänster i form av värdering av eller arbeten på en vara som är lös egendom. Lag (2013:368).\n\n## 13 §\n\nEn restaurang- eller cateringtjänst är omsatt inom landet, om den fysiskt utförs i Sverige och inte annat följer av 1 § tredje stycket eller 14 §. Lag (2009:1333).\n\n## 14 §\n\nEn restaurang- eller cateringtjänst som fysiskt utförs ombord på tåg under den del av en persontransport som genomförs inom EU är omsatt inom landet, om avgångsorten är belägen i Sverige.\n\nVid tillämpningen av första stycket gäller vad som föreskrivs i 2 b § andra till femte styckena. Lag (2011:283).\n\n## 15 §\n\nEn tjänst i form av korttidsuthyrning av transportmedel är omsatt inom landet om transportmedlet faktiskt ställs till förvärvarens förfogande i Sverige.\n\nMed korttidsuthyrning avses att transportmedlet får innehas eller användas under en sammanhängande period om högst\n\n1. 30 dagar, eller\n2. 90 dagar, när det gäller fartyg. Lag (2009:1333).\n\n## 15 a §\n\nEn tjänst som avser annan uthyrning av transportmedel än sådan som anges i 15 § och förvärvas av någon som inte är en beskattningsbar person är omsatt inom landet, om förvärvaren är etablerad, bosatt eller stadigvarande vistas i Sverige.\n\nEn uthyrningstjänst enligt första stycket är dock omsatt utomlands, om\n\n1. den avser en fritidsbåt som faktiskt levereras till förvärvaren i ett annat EU-land än Sverige, och\n2. uthyraren har sätet för sin ekonomiska verksamhet eller ett fast etableringsställe i det EU-landet och tjänsten tillhandahålls från sätet eller det fasta etableringsstället. Lag (2013:368).\n\n## 15 b §\n\nEn tjänst som avser annan uthyrning av transportmedel än sådan som anges i 15 § är omsatt inom landet, om\n\n1. den tillhandahålls någon som inte är en beskattningsbar person,\n2. den avser en fritidsbåt som faktiskt levereras till förvärvaren av tjänsten i Sverige, och\n3. uthyraren har sätet för sin ekonomiska verksamhet eller ett fast etableringsställe i Sverige och tjänsten tillhandahålls från sätet eller det fasta etableringsstället. Lag (2013:368).\n\n## 16 §\n\nTelekommunikationstjänster, radio- och tv-sändningar och elektroniska tjänster som förvärvas av någon som inte är en beskattningsbar person är omsatta inom landet, om förvärvaren är etablerad, är bosatt eller stadigvarande vistas i Sverige.\n\nFörsta stycket gäller inte för tjänster som är omsatta i ett annat EU-land enligt bestämmelser som i det landet motsvarar artikel 59c.1 i rådets direktiv 2006/112/EG.\n\nMed telekommunikationstjänster avses tjänster för\n\n1. överföring, sändning eller mottagning av signaler, skrift, bilder och ljud eller information i övrigt med hjälp av tråd, radio eller optiska eller andra elektromagnetiska medel, eller\n2. överlåtelse eller upplåtelse av en rättighet att utnyttja kapacitet för sådan överföring, sändning eller mottagning.\n\nElektroniska tjänster omfattar tjänster såsom tillhandahållande av\n\n1. webbplatser, webbhotell samt distansunderhåll av programvara och utrustning,\n2. programvara och uppdatering av denna,\n3. bilder, texter och uppgifter samt databasåtkomst,\n4. musik, filmer och spel, inklusive hasardspel och spel om pengar, samt politiska, kulturella, konstnärliga, idrottsliga, vetenskapliga eller underhållningsbetonade sändningar och evenemang, och\n5. distansundervisning. Lag (2020:1170).\n\n## 16 b §\n\nHar upphävts genom lag (2020:1170).\n\n## 17 §\n\nFöljande tjänster är omsatta utomlands, om de tillhandahålls från Sverige och förvärvas av någon som inte är en beskattningsbar person och förvärvaren är etablerad, är bosatt eller stadigvarande vistas i ett land utanför EU:\n\n1. överlåtelse eller upplåtelse av upphovsrätter, patenträttigheter, licensrättigheter, varumärkesrättigheter och liknande rättigheter,\n2. reklam- och annonseringstjänster,\n3. tjänster av rådgivare, ingenjörer, konsultbyråer, jurister och revisorer och andra liknande tjänster samt databehandling och tillhandahållande av information,\n4. bank- och finansieringstjänster utom uthyrning av förvaringsutrymmen, samt försäkrings- och återförsäkringstjänster,\n5. tillhandahållande av arbetskraft,\n6. uthyrning av andra varor som är lös egendom än transportmedel,\n7. förpliktelser att helt eller delvis avstå från att utnyttja en sådan rättighet som anges i 1 eller från att utöva en viss verksamhet,\n\n8. tillträde till och överföring eller distribution genom\n   a) ett naturgassystem som är beläget inom unionens territorium eller ett gasnät som är anslutet till ett sådant system,\n   b) ett system för el, eller\n   c) ett nät för värme eller kyla,\n9. tjänster som är direkt kopplade till sådana tjänster som avses i 8.\n\nTjänster som enligt första stycket är omsatta utomlands ska dock anses vara omsatta inom landet, om de faktiskt används och utnyttjas i Sverige. Lag (2014:940).\n\n## 18 §\n\nTjänster som anges i 17 § och som tillhandahålls från ett land utanför EU och som förvärvas av någon som inte är en beskattningsbar person är omsatta inom landet, om\n\n1. förvärvaren är etablerad, är bosatt eller stadigvarande vistas i Sverige, och\n2. tjänsterna faktiskt används och utnyttjas i Sverige. Lag (2014:940).\n\n### Undantag från 4-18 §§ och 9 b kap. 4 §\n\n## 19 §\n\nEn omsättning av tjänster enligt någon av 4–18 §§ eller 9 b kap. 4 § första stycket anses som omsättning utomlands när det är fråga om\n\n1. tjänster som avser luftfartyg i utrikes trafik, inräknat upplåtelse av flygplatser, eller tjänster som avser utrustning eller andra varor för användning på sådana luftfartyg,\n\n2. lastning, lossning, transport eller andra tjänster i direkt samband med\n   a) export av varor från Sverige eller ett annat EU-land,\n   b) import av varor som omfattas av\n\n- 9 c kap. 1 §, eller\n- ett förfarande för tillfällig införsel med fullständig befrielse från tull eller extern transitering,\n  c) försändelse, transport eller införsel av varor i fri omsättning, vilka införs i Sverige från ett tredje territorium som utgör en del av unionens tullområde, om varorna\n- förflyttas här i landet under ett förfarande för intern unionstransitering enligt unionens tullbestämmelser, om varorna hänfördes till samma förfarande genom en deklaration när de fördes in i landet samt försändelsen eller transporten av dem avslutas utanför Sverige, eller\n- när de förs in i Sverige hade omfattats av 9 c kap. 1 § eller ett förfarande för tillfällig införsel med fullständig befrielse från importtullar, om de hade importerats, eller\n  d) införsel av varor till ett annat EU-land om dessa omfattas av det landets tillämpning av artikel 61 eller 157.1 a i direktiv 2006/112/EG,\n\n3. tjänster som består av arbete på lös egendom, om egendomen förvärvats eller importerats för att undergå sådant arbete inom EU och egendomen efter det att arbetet utförts, transporteras ut ur EU av den som tillhandahåller tjänsterna, eller av kunden om denne inte är etablerad inom landet eller för någonderas räkning,\n4. förmedling av varor eller tjänster som görs för någon annans räkning i dennes namn, när omsättningen av dessa anses som en omsättning utanför EU antingen enligt 1 § första stycket eller enligt förevarande paragraf eller 3 a §, och\n5. en varutransporttjänst eller en tjänst som avses i 12 §, om tjänsten tillhandahålls en beskattningsbar person och den uteslutande nyttjas eller på annat sätt tillgodogörs utanför EU. Lag (2017:1196).\n\n### Tröskelvärde för beskattningsbara personer som utför unionsintern distansförsäljning av varor och tillhandahåller vissa tjänster\n\n## 20 §\n\nTjänster som anges i 16 § och varor som omfattas av 2 a § 1 är också omsatta inom landet, om\n\n1. säljaren är etablerad i Sverige men saknar etablering i något annat EU-land eller, om säljaren saknar etablering, är bosatt eller stadigvarande vistas här i landet men inte i något annat EU-land,\n2. tjänsterna förvärvas av någon som inte är en beskattningsbar person och som är etablerad, är bosatt eller stadigvarande vistas i ett annat EU-land, eller varorna sänds eller transporteras till ett annat EU-land, och\n3. det sammanlagda värdet, exklusive mervärdesskatt, av varorna och tjänsterna inte överstiger 99 680 kronor under innevarande kalenderår och inte heller översteg detta belopp under det närmast föregående kalenderåret. Lag (2020:1170).\n\n## 21 §\n\nOm det belopp som avses i 20 § 3 överskrids är tjänsterna eller varorna omsatta utomlands. Detta gäller från och med den omsättning som medför att beloppet överskrids.\n\nÄven om villkoren i 20 § är uppfyllda får säljaren begära att omsättningarna anses gjorda där förvärvaren av tjänsterna är etablerad, är bosatt eller stadigvarande vistas eller där försändningen eller transporten av varorna till förvärvaren avslutas. Skatteverket ska då besluta att tjänsterna eller varorna är omsatta utomlands. Beslutet gäller tills vidare. Bestämmelsen i 20 § får inte tillämpas igen förrän efter utgången av det andra kalenderåret efter det kalenderår då beslutet fattades. Lag (2020:1170).\n\n# 8 kap. Avdrag för ingående skatt\n\n## 1 §\n\nAvdrag för ingående skatt får göras enligt bestämmelserna i detta kapitel.\n\nI 9 kap. finns särskilda bestämmelser om avdrag och jämkning av avdrag för ingående skatt som hänför sig till förvärv i verksamheter som avser vissa fastighetsupplåtelser. Lag (2000:500).\n\n## 1 a §\n\nDen som redovisar mervärdesskatt enligt 4 a §, 4 e § 1 b eller 4 e § 1 c lagen (2011:1245) om särskilda ordningar för mervärdesskatt för distansförsäljning av varor och för tjänster eller enligt motsvarande bestämmelser i ett annat EU- land har inte rätt till avdrag för ingående skatt.\n\nDen som redovisar mervärdesskatt enligt 4 b §, 4 c §, 4 d § eller 4 e § 1 a samma lag eller enligt bestämmelser som i ett annat EU-land motsvarar artiklarna 369a-369k i rådets direktiv 2006/112/EG har inte rätt till avdrag för ingående skatt avseende förvärv eller import i de verksamheter som omfattas av bestämmelserna. Detsamma gäller den som är etablerad i ett annat EU-land och redovisar mervärdesskatt enligt bestämmelser som i det landet motsvarar artiklarna 369l-369x i direktivet.\n\nDen som är eller ska vara registrerad till mervärdesskatt i Sverige för annan verksamhet än sådan som omfattas av bestämmelserna i första och\n\nandra styckena, får dock göra avdrag enligt detta kapitel för ingående skatt\n\navseende förvärv eller import som hänför sig till de verksamheter i Sverige som omfattas av bestämmelserna.\n\nI 10 kap. 4 a § finns bestämmelser om återbetalning av ingående skatt i de fall avdrag inte får göras enligt första eller andra stycket. Lag (2020:1170).\n\n## 2 §\n\nIngående skatt utgörs av beloppet av den skatt enligt denna lag som hänför sig till ersättning för förvärv av varor eller tjänster, om omsättningen medfört skattskyldighet för den från vilken varorna eller tjänsterna förvärvats.\n\nVid förvärv som medför skattskyldighet enligt 1 kap. 2 § första stycket 2–5 eller om skattskyldighet föreligger för förvärvaren enligt 9 c kap. 5 § utgörs ingående skatt av beloppet av den utgående skatt som den skattskyldige skall redovisa till staten.\n\nI det fall en förvärvare enligt 8 a kap.11–14 §§ övertar överlåtarens rättigheter och skyldigheter när det gäller jämkning utgörs förvärvarens ingående skatt för de övertagna investeringsvarorna av överlåtarens ingående skatt för varorna.\n\nIngående skatt utgörs också av skatt enligt denna lag som hänför sig till\n\n1. förvärv enligt 4 § första stycket 4 eller 9 kap. 8 § andra stycket 2,\n2. import till landet, eller\n3. skattepliktiga uttag som avses i 4 § 5.Lag (2016:1208).\n\n## 3 §\n\nDen som bedriver en verksamhet som medför skattskyldighet får göra avdrag för den ingående skatt som hänför sig till förvärv eller import i verksamheten.\n\nDen skattskyldiges avdragsrätt omfattar även ingående skatt som hänför sig till förvärv eller import för avhjälpande av skador som uppstått i verksamheten även då den som vållat skadan eller en försäkringsgivare står för kostnaden för förvärvet eller importen. Lag (1994:1798).\n\n## 4 §\n\nDen som bedriver en verksamhet som medför skattskyldighet får också göra avdrag\n\n1. om den skattskyldige från någon annan skattskyldig eller någon som har rätt till återbetalning enligt 10 kap.9 eller 11–13 §§ har övertagit verksamheten eller en del av den: för den ingående skatt som hänför sig till den tidigare ägarens förvärv för verksamheten, om den tidigare ägaren inte har gjort avdrag för eller fått återbetalning av den ingående skatten men skulle ha varit berättigad till sådant avdrag eller sådan återbetalning om den tidigare ägaren hade fortsatt att driva verksamheten,\n2. om den skattskyldige är delägare i en samfällighet för vattenreglering, väghållning eller liknande ändamål och den fastighet som ingår i samfälligheten används i den verksamhet som medför skattskyldighet: för den ingående skatt som hänför sig till samfällighetens förvärv, dock endast till den del som svarar mot den skattskyldiges andel i samfälligheten,\n3. om den skattskyldige fått en vara levererad till sig och då har betalat skatt vid importen av varan utan att vara skattskyldig för importen eller om den skattskyldige har betalat ersättning för denna skatt till den som haft sådan skattskyldighet: för den skatt som Tullverket tagit ut, dock endast under förutsättning att leverantören inte är skattskyldig enligt denna lag för annat än importen och den skattskyldige skulle ha haft avdragsrätt om den skattskyldige själv hade varit skattskyldig för importen,\n4. om den skattskyldige köper en fastighet, hyresrätt eller en bostadsrätt till en lägenhet och fastigheten eller lägenheten i säljarens byggnadsrörelse har tillförts tjänster, vilkas tillförande utgör skattepliktiga uttag enligt 2 kap. 7 §, utan att fastigheten eller lägenheten därefter har tagits i bruk av säljaren: för den utgående skatt som säljaren har redovisat eller ska redovisa för uttagen, eller\n5. om den skattskyldige i sin byggnadsrörelse tillfört en egen fastighet eller en lägenhet som innehas med hyresrätt eller bostadsrätt tjänster som utgör skattepliktiga uttag enligt 2 kap. 7 § och fastigheten eller lägenheten därefter tas i bruk av den skattskyldige i en verksamhet som medför skattskyldighet eller rätt till återbetalning av ingående skatt enligt 10 kap. 9, 11 eller 12 §: för den utgående skatt som fastighetsägaren, hyresgästen eller bostadsrättshavaren har redovisat eller ska redovisa för uttagen. Lag (2015:888).\n\n## 4 a §\n\nIngående skatt som är avdragsgill enligt 3 § och hänför sig till en fastighet får endast dras av i proportion till den omfattning en skattskyldig använder den i sin verksamhet, om skatten hänför sig till en fastighet som både används\n\n1. av den skattskyldige i verksamheten, och\n\n2. för\n\n- eget privat bruk,\n- personalens privata bruk, eller\n- annars annat ändamål än för den egna verksamheten.\n\nMed ingående skatt avses i första stycket även sådan skatt som hänför sig till ny-, till- eller ombyggnad eller reparation av en fastighet.\n\nFörsta stycket gäller inte\n\n1. en stadigvarande bostad som omfattas av avdragsförbudet som följer av 9 och 10 §§, eller\n2. ingående skatt som är avdragsgill enligt 10 §. Lag (2010:1892).\n\n## 4 b §\n\nOm den enligt 4 a § avdragsgilla delen av den ingående skatten inte kan fastställas, får avdragsbeloppet i stället bestämmas genom uppdelning efter skälig grund. Lag (2010:1892).\n\n## 4 c §\n\nOm användningen av en sådan fastighet som avses i 4 a § ändras, ska den ingående skatten jämkas i enlighet med 8 a kap.\n\nBestämmelserna i 2 kap. 5 § är inte tillämpliga vid ändrad användning av en sådan fastighet som avses i 4 a §. Lag (2010:1892).\n\n## 5 §\n\nRätt till avdrag för ingående skatt föreligger endast om den kan styrkas enligt vad som föreskrivs i 17, 19 och 20 §§. Lag (2000:500).\n\n### Den ingående skattens storlek\n\n## 6 §\n\nDen ingående skatten uppgår till samma belopp som den utgående skatten hos den som är skattskyldig för omsättningen eller importen.\n\nI 13 kap. 23 a § finns bestämmelser om redovisning av ingående skatt när skattebeloppet angetts i flera valutor i fakturan eller när skattebeloppet måste räknas om till svenska kronor.\n\nI 13 kap. 26 § finns bestämmelser om återförande av sådan ingående skatt som hänför sig till ett förvärv för vilket en skattskyldig har fått prisnedsättning efter det att han gjort avdrag för skatten. Lag (2012:342).\n\n## 7 §\n\nVid förvärv enligt 4 § första stycket 4 uppgår den ingående skatten till den där angivna utgående skatten hos säljaren. Lag (2007:1376).\n\n### Begränsningar av avdragsrätten\n\n## 8 §\n\nStaten har inte någon avdragsrätt för ingående skatt.\n\n## 9 §\n\nAvdrag får inte göras för sådan ingående skatt som hänför sig till\n\n1. stadgivarande bostad om inte annat följer av 10 §,\n2. utgifter för representation och liknande ändamål för vilka den skattskyldige inte har rätt att göra avdrag vid inkomstbeskattningen enligt 16 kap. 2 § inkomstskattelagen (1999:1229),\n3. förvärv av varor för försäljning från fartyg på linjer mellan Sverige och Norge eller Sverige och Åland, eller\n4. kostnader vid uttag av tjänst där beskattningsunderlaget beräknats enligt 7 kap. 5 § andra stycket.\n\nFör sådana utgifter som avses i första stycket 2 får avdrag dock göras för ingående skatt som avser måltider eller liknande förtäring, om\n\n1. utgifterna har ett sådant omedelbart samband med verksamheten som avses i 16 kap. 2 § inkomstskattelagen,\n2. avdraget inte överstiger vad som kan anses skäligt, och\n3. avdraget högst uppgår till den ingående skatten på 300 kronor per person och tillfälle.\n\nAvdragsbegränsningen i första stycket 3 gäller inte om förvärven avser spritdrycker, vin, starköl, öl, tobaksvaror, parfymer, kosmetiska preparat, toalettmedel eller choklad- och konfektyrvaror. I fråga om punktskattepliktiga varor är det dock en förutsättning för avdrag att varorna får provianteras utan punktskatt enligt 5–9 §§ lagen (1999:446) om proviantering av fartyg och luftfartyg.\n\nI 9 a kap. 13 § och 9 b kap. 3 § finns ytterligare begränsningar av rätten till avdrag för ingående skatt. Lag (2017:1196).\n\n## 10 §\n\nAvdragsförbudet i 9 § 1 gäller inte om den ingående skatten hänför sig till förvärv eller import för utförande av sådana tjänster som avses i 2 kap.7 eller 8 § och för vilka uttagsbeskattning skall ske med stöd av bestämmelserna i 2 kap. Avdrag får också göras för ingående skatt som hänför sig till ett jordbruksarrende även till den del arrendet omfattar bostad.\n\nI 15 § och 16 § första stycket 2 finns särskilda begränsningar av rätten till avdrag för ingående skatt som hänför sig till förvärv eller hyra av personbilar eller motorcyklar. Lag (1994:1798).\n\n## 11 §\n\nEtt finansieringsföretag som har övertagit en säljares rätt enligt ett köpeavtal får göra avdrag för den ingående skatt som hänför sig till värdet av en vara som med stöd av köpeavtalet återtas av finansieringsföretaget. Detta gäller dock endast om företaget kan visa att köparen helt saknat rätt till avdrag för ingående skatt och inte heller haft rätt till återbetalning enligt 10 kap.9-13 §§ av någon del av sådan skatt.\n\n### Uppdelning av den ingående skatten i vissa fall\n\n## 13 §\n\nI de fall den ingående skatten endast delvis avser förvärv eller import som medför avdragsrätt eller avser förvärv eller import som görs gemensamt för flera verksamheter, av vilka någon inte medför skattskyldighet, eller görs för en verksamhet som endast delvis medför skattskyldighet får avdrag göras endast för skatten på den del av ersättningen eller inköpspriset som hänför sig till den del av förvärvet eller importen som medför avdragsrätt respektive hänför sig till verksamhet som medför skattskyldighet. Om denna del inte kan fastställas, får avdragsbeloppet i stället bestämmas genom uppdelning efter skälig grund.\n\nFörsta stycket gäller inte om annat följer av 14 eller 16 §. Lag (2007:1376).\n\n## 14 §\n\nOm den ingående skatten avser förvärv eller import för verksamhet som endast delvis medför skattskyldighet, får hela den ingående skatten för ett visst förvärv eller en viss import ändå dras av\n\n1. om förvärvet eller importen till mer än 95 procent görs för den del av verksamheten som medför skattskyldighet, eller\n2. om skatten för förvärvet eller importen inte överstiger 1 000 kronor och mer än 95 procent av omsättningen i verksamheten medför skattskyldighet.\n\nOm den ingående skatten avser förvärv eller import för en verksamhet som medför både skattskyldighet och återbetalningsrätt enligt 10 kap.9-13 §§ eller för både en verksamhet som medför skattskyldighet och en annan verksamhet som medför sådan återbetalningsrätt, behöver någon uppdelning av den ingående skatten enligt 13 § inte göras. Lag (1994:1798).\n\n### Personbilar och motorcyklar\n\n## 15 §\n\nNär personbilar eller motorcyklar förvärvas eller förhyrs för andra ändamål än återförsäljning, uthyrning, persontransporter enligt taxitrafiklagen (2012:211), transporter av avlidna eller körkortsutbildning som omfattas av skatteplikt får avdrag inte göras för ingående skatt som hänför sig till\n\n1. förvärv av fordonet, eller\n2. förhyrning av fordonet om det i endast ringa omfattning används i den verksamhet som medför skattskyldighet. Lag (2012:215).\n\n## 16 §\n\nEn skattskyldig som använder en personbil eller motorcykel i en verksamhet som medför skattskyldighet får dra av\n\n1. ingående skatt som hänför sig till driftskostnader för sådan användning, utan någon begränsning på grund av att fordonet endast delvis används i verksamheten, och\n2. hälften av den ingående skatt som hänför sig till förhyrning av fordonet för sådan användning, utan någon begränsning på grund av att fordonet endast delvis används i verksamheten.\n\nFörsta stycket 1 gäller endast om fordonet tillhör inventarierna i verksamheten eller har förhyrts för användning i denna. Första stycket 2 gäller inte om fordonet har förhyrts för persontransporter i taxitrafik, uthyrning, transport av avlidna eller körkortsutbildning som omfattas av skatteplikt eller om den ingående skatten omfattas av avdragsförbudet i 15 § 2.Lag (2012:215).\n\n### Hur rätten till avdrag skall styrkas\n\n## 17 §\n\nVid förvärv av vara eller tjänst från någon som är skattskyldig eller om förvärvaren är skattskyldig enligt 1 kap. 2 § första stycket 2-5 ska avdragsrätten styrkas genom faktura.\n\nOm det finns särskilda skäl behövs ingen faktura, om förvärvaren är skattskyldig och kan styrka avdragsrätten genom annan tillgänglig dokumentation. Lag (2012:342).\n\n## 19 §\n\nVid förvärv av en fastighet eller en lägenhet som innehas med hyresrätt eller bostadsrätt ska den ingående skatten enligt 4 § första stycket 4 eller 9 kap. 8 § andra stycket 2 styrkas genom en av överlåtaren utfärdad handling i pappersform eller i elektronisk form. Överlåtaren är skyldig att utfärda en sådan handling om förvärvaren begär det.\n\nOm handlingen utfärdas på grund av överlåtelse som avses i 4 § första stycket 4, ska den innehålla uppgift om den utgående skatt som överlåtaren har redovisat eller ska redovisa för gjorda skattepliktiga uttag av tjänster på fastigheten eller lägenheten.\n\nOm handlingen utfärdas på grund av överlåtelse som avses i 9 kap. 8 § andra stycket 2, ska den innehålla uppgift om den ingående skatt som hänför sig till ny-, till- eller ombyggnad och som överlåtaren inte har dragit av.\n\nUtöver de uppgifter som anges i andra och tredje styckena ska den handling som avses där innehålla uppgift om\n\n1. överlåtarens och förvärvarens namn och adress eller någon annan uppgift genom vilken de kan identifieras,\n2. transaktionens art,\n3. överlåtarens registreringsnummer till mervärdesskatt eller, då denne inte är registrerad, person- eller organisationsnummer om det finns ett sådant och annars en likvärdig uppgift, och\n4. övrigt som kan ha betydelse för bedömningen av skattskyldigheten och förvärvarens avdragsrätt eller rätt till återbetalning. Lag (2007:1376).\n\n## 20 §\n\nDen som enligt 8 a kap.11-14 §§ skall överta överlåtarens rättighet och skyldighet när det gäller jämkning av avdrag för ingående skatt skall som grund för jämkningen i sina räkenskaper ha en av överlåtaren utfärdad handling som avses i 8 a kap. 15 §. Lag (2003:1134).\n",
}
